-- C. ALT ÖLÇÜTLER VE YÖKAK DEĞERLENDİRME RUBRİKLERİ (59 ADET)
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (6, 'A.1.1', 'Misyon, Vizyon, Stratejik Amaçlar ve Hedefler', 'Mission, Vision, Strategic Goals and Objectives', 'الرسالة والرؤية والأهداف والغايات الاستراتيجية', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda stratejik plan kapsamında tanımlanmış misyon, vizyon, stratejik amaçlar bulunmamaktadır.","2":"Kurumun stratejik plan kapsamında tanımlanmış misyon, vizyon, stratejik amaç ve hedefleri bulunmaktadır. Ancak bunları gerçekleştirmek amacıyla yapılan uygulamalar bulunmamaktadır veya mevcut uygulamalar tüm alanları kapsamamaktadır.","3":"Stratejik plan kapsamında stratejik amaçları ve hedefleri doğrultusunda kurumun tamamında yapılan uygulamalar bulunmaktadır ve bu uygulamalardan bazı sonuçlar elde edilmiştir. Ancak stratejik planın izlenmesi için gerekli mekanizmalar oluşturulmamıştır ve/veya stratejik plan ve/veya herhangi bir karar alma sürecinde kullanılmamaktadır.","4":"Stratejik plan kapsamında stratejik amaçlar ve hedefler doğrultusundaki tüm alanları kapsayan uygulamalar sistematik olarak ve kurumun iç kalite güvencesi sistemi ile uyumlu olarak izlenmekte ve paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Stratejik plan kapsamında stratejik amaç ve hedefleri gerçekleştirmek üzere yapılan olgunlaşmış, sürdürülebilir uygulamalar kurumun tamamında benimsenmiştir; kurumun bu hususta kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no mission, vision or strategic objectives defined within the scope of the strategic plan in the institution.","2":"The institution has a mission, vision, strategic goals and objectives defined within the scope of the strategic plan. However, there are no applications to achieve these or existing applications do not cover all areas.","3":"Within the scope of the strategic plan, there are practices carried out throughout the institution in line with its strategic goals and objectives, and some results have been obtained from these practices. However, the necessary mechanisms for monitoring the strategic plan have not been established and/or are not used in the strategic plan and/or any decision-making process.","4":"Within the scope of the strategic plan, practices covering all areas in line with strategic goals and objectives are monitored systematically and in accordance with the institution''s internal quality assurance system, and measures are taken by evaluating them together with stakeholders.","5":"Mature, sustainable practices implemented to achieve strategic goals and objectives within the scope of the strategic plan have been adopted throughout the institution; The institution has many unique and innovative practices in this regard, and some of these practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد رسالة أو رؤية أو أهداف استراتيجية محددة ضمن نطاق الخطة الاستراتيجية في المؤسسة.","2":"للمؤسسة رسالة ورؤية وأهداف إستراتيجية وغايات محددة ضمن نطاق الخطة الإستراتيجية. ومع ذلك، لا توجد تطبيقات لتحقيق هذه الأهداف أو أن التطبيقات الموجودة لا تغطي جميع المجالات.","3":"يوجد ضمن نطاق الخطة الإستراتيجية ممارسات يتم تنفيذها في جميع أنحاء المؤسسة بما يتوافق مع أهدافها وغاياتها الإستراتيجية، وقد تم الحصول على بعض النتائج من هذه الممارسات. ومع ذلك، لم يتم إنشاء الآليات اللازمة لمراقبة الخطة الإستراتيجية و/أو لم يتم استخدامها في الخطة الإستراتيجية و/أو أي عملية صنع قرار.","4":"في نطاق الخطة الإستراتيجية، تتم مراقبة الممارسات التي تغطي جميع المجالات بما يتماشى مع الأهداف والغايات الإستراتيجية بشكل منهجي ووفقًا لنظام ضمان الجودة الداخلي للمؤسسة، ويتم اتخاذ التدابير من خلال تقييمها مع أصحاب المصلحة.","5":"تم اعتماد الممارسات الناضجة والمستدامة التي تم تنفيذها لتحقيق الأهداف والغايات الإستراتيجية ضمن نطاق الخطة الإستراتيجية في جميع أنحاء المؤسسة؛ ولدى المؤسسة العديد من الممارسات الفريدة والمبتكرة في هذا الصدد، وبعض هذه الممارسات تتخذها مؤسسات أخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (7, 'A.1.2', 'Kalite Güvencesi, Eğitim Öğretim, Araştırma Geliştirme, Toplumsal Katkı ve Yönetim Sistemi Politikaları', 'Quality Assurance, Education and Training, Research and Development, Social Contribution and Management System Policies', 'ضمان الجودة، التعليم والتدريب، البحث والتطوير، المساهمة الاجتماعية وسياسات نظام الإدارة', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda tanımlı herhangi bir politika bulunmamaktadır.","2":"Kurumda kalite güvencesi, eğitim-öğretim, araştırma-geliştirme, toplumsal katkı ve yönetim sistemi gibi temel alanların bazılarında tanımlı politikalar bulunmaktadır. Ancak bu politikalar herhangi bir planlama veya karar alma süreçlerinde kullanılmamaktadır.","3":"Kalite güvencesi, eğitim ve öğretim, araştırma ve geliştirme, toplumsal katkı ve yönetim sistemi alanlarının tümünde tanımlı politikalar doğrultusunda yapılan uygulamalar bulunmaktadır ve bu uygulamalardan bazı sonuçlar elde edilmiştir. Ancak bu uygulamaların sonuçlarını izlemek için gerekli mekanizmalar bulunmamaktadır.","4":"Kalite güvencesi, eğitim ve öğretim, araştırma ve geliştirme, toplumsal katkı ve yönetim sistemi alanlarındaki kurumsal politikaların birbirleri ile olan ilişkileri kurulmuş ve politikalardaki bu bütüncül yapı iç kalite güvence sistemini yönlendirmektedir; sonuçlar izlenmekte ve paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Tüm başlıklardaki kurumsal politikalar doğrultusunda olgunlaşmış, sürdürülebilir uygulamalar kurumun tamamında benimsenmiştir ve karar almalarda esas alınmaktadır; bu uygulamalar içerisinde kuruma özgü ve yenilikçi birçok uygulama bulunmakta, uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no defined policy in the institution.","2":"The institution has defined policies in some of the basic areas such as quality assurance, education-training, research-development, social contribution and management system. However, these policies are not used in any planning or decision-making processes.","3":"There are practices carried out in line with defined policies in all areas of quality assurance, education and training, research and development, social contribution and management system, and some results have been obtained from these practices. However, there are no necessary mechanisms to monitor the results of these practices.","4":"The interrelationships of corporate policies in the fields of quality assurance, education and training, research and development, social contribution and management system have been established and this holistic structure in policies directs the internal quality assurance system; The results are monitored and evaluated together with stakeholders and precautions are taken.","5":"Mature, sustainable practices in line with corporate policies under all headings have been adopted throughout the institution and are taken as basis in decision-making; Among these applications, there are many institution-specific and innovative applications, and some of the applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد سياسة محددة في المؤسسة.","2":"وقد حددت المؤسسة سياسات في بعض المجالات الأساسية مثل ضمان الجودة والتعليم والتدريب وتطوير البحوث والمساهمة الاجتماعية ونظام الإدارة. ومع ذلك، لا يتم استخدام هذه السياسات في أي عمليات التخطيط أو اتخاذ القرار.","3":"هناك ممارسات يتم تنفيذها بما يتماشى مع سياسات محددة في جميع مجالات ضمان الجودة والتعليم والتدريب والبحث والتطوير والمساهمة الاجتماعية ونظام الإدارة، وقد تم الحصول على بعض النتائج من هذه الممارسات. إلا أنه لا توجد آليات ضرورية لرصد نتائج هذه الممارسات.","4":"تم إنشاء العلاقات المتبادلة بين سياسات الشركات في مجالات ضمان الجودة والتعليم والتدريب والبحث والتطوير والمساهمة الاجتماعية ونظام الإدارة، وهذا الهيكل الشامل في السياسات يوجه نظام ضمان الجودة الداخلي؛ ويتم رصد النتائج وتقييمها بالتعاون مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تم اعتماد ممارسات ناضجة ومستدامة تتماشى مع سياسات الشركة تحت جميع العناوين في جميع أنحاء المؤسسة ويتم اتخاذها كأساس في عملية صنع القرار؛ ومن بين هذه التطبيقات، هناك العديد من التطبيقات الخاصة بالمؤسسات والمبتكرة، وبعض التطبيقات تتخذ كمثال من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (8, 'A.1.3', 'Kurumsal Performans Yönetimi', 'Corporate Performance Management', 'إدارة أداء الشركات', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda performans yönetimi uygulaması ve stratejik planla uyumlu olarak tanımlanmış performans göstergeleri bulunmamaktadır.","2":"Kurumda performansı izlemek üzere bazı göstergeler ve mekanizmalar tanımlanmıştır. Ancak bu göstergeleri izlemek üzere yapılan uygulamalar bulunmamaktadır veya mevcut uygulamalar tüm alanları/süreçleri (kalite güvencesi sistemi, eğitim ve öğretim, araştırma ve geliştirme, toplumsal katkı, yönetim sistemi) kapsamamaktadır.","3":"Tüm alanlarla ilişkili olarak performans göstergeleri ve anahtar performans göstergeleri belirlenmiştir. Ancak bu göstergelerin izlenmesi sistematik olmayan ve tüm alanları kapsamayan şekilde yapılmaktadır.","4":"Tüm alanlarla/süreçlerle ilişkili tüm performans göstergeleri sistematik ve kurumun iç kalite güvencesi sistemi ile uyumlu olarak izlenmekte ve elde edilen sonuçlar paydaşlarla birlikte değerlendirilerek karar almalarda kullanılmakta ve performans yönetimine ilişkin önlemler alınmaktadır.","5":"Kurumsal amaçlar doğrultusunda, olgunlaşmış ve sürdürülebilir kurumsal performans yönetimi kurumun tamamında benimsenmiştir; kuruma özgü ve yenilikçi uygulamalar bulunmakta, uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no performance indicators defined in line with the performance management practice and strategic plan in the institution.","2":"Some indicators and mechanisms have been defined to monitor performance in the institution. However, there are no practices to monitor these indicators, or existing practices do not cover all areas/processes (quality assurance system, education and training, research and development, social contribution, management system).","3":"Performance indicators and key performance indicators have been determined in relation to all areas. However, monitoring of these indicators is done in a non-systematic way and does not cover all areas.","4":"All performance indicators related to all areas/processes are monitored systematically and in compliance with the institution''s internal quality assurance system, and the results obtained are evaluated together with stakeholders and used in decision-making and performance management measures are taken.","5":"In line with corporate objectives, mature and sustainable corporate performance management has been adopted throughout the institution; There are institution-specific and innovative practices, and some of the practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد مؤشرات أداء محددة تتوافق مع ممارسة إدارة الأداء والخطة الإستراتيجية في المؤسسة.","2":"وتم تحديد بعض المؤشرات والآليات لمراقبة الأداء في المؤسسة. ومع ذلك، لا توجد ممارسات لرصد هذه المؤشرات، أو أن الممارسات الحالية لا تغطي جميع المجالات/العمليات (نظام ضمان الجودة، التعليم والتدريب، البحث والتطوير، المساهمة الاجتماعية، نظام الإدارة).","3":"وقد تم تحديد مؤشرات الأداء ومؤشرات الأداء الرئيسية فيما يتعلق بجميع المجالات. إلا أن رصد هذه المؤشرات يتم بشكل غير منهجي ولا يشمل جميع المجالات.","4":"تتم مراقبة جميع مؤشرات الأداء المتعلقة بجميع المجالات/ العمليات بشكل منهجي وبما يتوافق مع نظام ضمان الجودة الداخلي للمؤسسة، ويتم تقييم النتائج التي تم الحصول عليها مع أصحاب المصلحة واستخدامها في اتخاذ القرارات وإجراءات إدارة الأداء.","5":"تماشيًا مع أهداف الشركة، تم اعتماد إدارة أداء مؤسسية ناضجة ومستدامة في جميع أنحاء المؤسسة؛ هناك ممارسات خاصة بالمؤسسة ومبتكرة، ويتم أخذ بعض الممارسات كمثال من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (9, 'A.2.1', 'Birim Kalite Komisyonu', 'Unit Quality Commission', 'لجنة الجودة بالوحدة', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda kalite güvencesi süreçlerini yürütmek üzere oluşturulmuş bir kalite komisyonu bulunmamaktadır.","2":"Kalite komisyonunun yetki, görev ve soru mlulukları ile organizasyon yapısı tanımlanmıştır. Ancak kalite komisyonu bu yetki, görev ve sorumluluklar kapsamında planlama ve/veya karar alma süreçlerinde etkin rol almamaktadır.","3":"Kalite komisyonunu yetki, görev ve sorumlulukları kapsamında çalışmalarını kapsayıcı ve katılımcı bir yaklaşımla şeffaf olarak yürütmektedir. Ancak bu uygulamalar kurumdaki bütüncül kalite yönetimi kapsamında yürütülmemektedir ve uygulamaların sonuçları izlenmemektedir.","4":"Kalite komisyonu yetki, görev ve sorumlulukları doğrultusunda sistematik ve kurumdaki bütüncül kalite yönetimi kapsamında çalışmalarını yürütmekte; yürütülen uygulamalardan elde edilen bulgular izlenmekte ve izlem sonuçları değerlendirilerek iyileştirmeler gerçekleştirilmektedir.","5":"Kalite komisyonunun kurumsal amaçlar doğrultusunda, sürdürülebilir ve bütünleşik uygulamaları kurumun tamamında benimsenmiştir; kurumun kalite yönetimi kapsamında yenilikçi uygulamaları bulunmakta, uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no quality commission established to carry out quality assurance processes in the institution.","2":"The authority, duties and responsibilities of the quality commission and its organizational structure are defined. However, the quality commission does not take an active role in the planning and/or decision-making processes within the scope of these authorities, duties and responsibilities.","3":"The quality commission carries out its work transparently, with an inclusive and participatory approach, within the scope of its powers, duties and responsibilities. However, these practices are not carried out within the scope of holistic quality management in the institution and the results of the practices are not monitored.","4":"The quality commission carries out its work within the scope of systematic and holistic quality management in the institution, in line with its authority, duties and responsibilities; The findings obtained from the practices carried out are monitored and improvements are made by evaluating the monitoring results.","5":"In line with the corporate objectives of the quality commission, sustainable and integrated practices have been adopted throughout the institution; The institution has innovative practices within the scope of quality management, and some of the practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد لجنة جودة تم إنشاؤها لتنفيذ عمليات ضمان الجودة في المؤسسة.","2":"تم تحديد صلاحيات وواجبات ومسؤوليات لجنة الجودة وهيكلها التنظيمي. ومع ذلك، لا تقوم لجنة الجودة بدور نشط في عمليات التخطيط و/أو اتخاذ القرار ضمن نطاق هذه السلطات والواجبات والمسؤوليات.","3":"وتمارس لجنة الجودة عملها بشفافية، وبمنهج شامل وتشاركي، في نطاق صلاحياتها وواجباتها ومسؤولياتها. ومع ذلك، لا يتم تنفيذ هذه الممارسات ضمن نطاق إدارة الجودة الشاملة في المؤسسة ولا يتم مراقبة نتائج الممارسات.","4":"تنفذ لجنة الجودة عملها ضمن نطاق إدارة الجودة المنهجية والشاملة في المؤسسة، بما يتماشى مع صلاحياتها وواجباتها ومسؤولياتها؛ ويتم رصد النتائج التي تم الحصول عليها من الممارسات المنفذة ويتم إجراء تحسينات من خلال تقييم نتائج الرصد.","5":"وتمشيا مع الأهداف المؤسسية للجنة الجودة، تم اعتماد ممارسات مستدامة ومتكاملة في جميع أنحاء المؤسسة؛ تمتلك المؤسسة ممارسات مبتكرة في نطاق إدارة الجودة، ويتم أخذ بعض الممارسات كمثال من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (10, 'A.2.2', 'İç Kalite Güvencesi Mekanizmaları', 'Internal Quality Assurance Mechanisms', 'آليات ضمان الجودة الداخلية', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun iç kalite güvencesi sistemi ve mekanizmaları bulunmamaktadır.","2":"Kurumun iç kalite güvencesi mekanizmaları bulunmaktadır ancak bu mekanizmalar bütün alanları/süreçleri (eğitim v e öğretim, araştırma ve geliştirme, toplumsal katkı, yönetim sistemi) kapsamamaktadır.","3":"Kurumun tüm alanları ve süreçleri kapsayacak şekilde iç kalite güvencesi mekanizmaları (süreçler, PUKÖ çevrimleri, görevler, yetki ve sorumluluklar, kalite araçları) bulunmakta olup; bu iç kalite güvencesi mekanizmalarından bazı uygulama sonuçları elde edilmiştir. Ancak bu mekanizmalar kurumdaki bütüncül kalite yönetimi kapsamında yürütülmemektedir ve uygulamaların sonuçları izlenmemektedir.","4":"Kurumda tüm alanları ve süreçleri kapsayan iç kalite güvencesi mekanizmaları, tanımlı süreçler bütüncül bir kalite yönetimi anlayışı kapsamında sistematik olarak yürütülmektedir; yürütülen uygulamalardan elde edilen bulgular izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlen dirilerek iyileştirmeler gerçekleştirilmektedir.","5":"Tüm alanları ve süreçleri kapsayan, kurumsal amaçlar doğrultusunda, sürdürülebilir ve bütünleşik iç kalite güvencesi uygulamaları kurumun tamamında benimsenmiştir. Kurumun kalite yönetimi kapsamında yenilikçi uygulamaları bulunmakta, uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have an internal quality assurance system and mechanisms.","2":"The institution has internal quality assurance mechanisms, but these mechanisms do not cover all areas/processes (education and training, research and development, social contribution, management system).","3":"The institution has internal quality assurance mechanisms (processes, PDCA cycles, duties, authorities and responsibilities, quality tools) covering all areas and processes; Some implementation results have been obtained from these internal quality assurance mechanisms. However, these mechanisms are not implemented within the scope of holistic quality management in the institution and the results of the applications are not monitored.","4":"Internal quality assurance mechanisms and defined processes covering all areas and processes in the institution are carried out systematically within the scope of a holistic quality management approach; The findings obtained from the implemented practices are monitored and the monitoring results are evaluated together with the stakeholders and improvements are made.","5":"Sustainable and integrated internal quality assurance practices, covering all areas and processes, in line with corporate objectives, have been adopted throughout the institution. The institution has innovative practices within the scope of quality management, and some of the practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا يوجد لدى المؤسسة نظام وآليات داخلية لضمان الجودة.","2":"تمتلك المؤسسة آليات داخلية لضمان الجودة، لكن هذه الآليات لا تغطي جميع المجالات/العمليات (التعليم والتدريب، البحث والتطوير، المساهمة الاجتماعية، نظام الإدارة).","3":"لدى المؤسسة آليات داخلية لضمان الجودة (العمليات، دورات PDCA، الواجبات، السلطات والمسؤوليات، أدوات الجودة) تغطي جميع المجالات والعمليات؛ وقد تم الحصول على بعض نتائج التنفيذ من آليات ضمان الجودة الداخلية هذه. إلا أن هذه الآليات لا يتم تنفيذها ضمن نطاق إدارة الجودة الشاملة في المؤسسة ولا يتم مراقبة نتائج التطبيقات.","4":"يتم تنفيذ آليات ضمان الجودة الداخلية والعمليات المحددة التي تغطي جميع المجالات والعمليات في المؤسسة بشكل منهجي ضمن نطاق نهج شامل لإدارة الجودة؛ يتم رصد النتائج التي تم الحصول عليها من الممارسات المنفذة ويتم تقييم نتائج الرصد مع أصحاب المصلحة ويتم إجراء التحسينات.","5":"تم اعتماد ممارسات ضمان الجودة الداخلية المستدامة والمتكاملة، والتي تغطي جميع المجالات والعمليات، بما يتماشى مع أهداف الشركة، في جميع أنحاء المؤسسة. تمتلك المؤسسة ممارسات مبتكرة في نطاق إدارة الجودة، ويتم أخذ بعض الممارسات كمثال من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (11, 'A.2.3', 'Liderlik ve Kalite Güvencesi Kültürü', 'Culture of Leadership and Quality Assurance', 'ثقافة القيادة وضمان الجودة', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda kalite güvencesi kültürünü destekleyen kurumsal kültür ve liderlik yaklaşımı bulunmamaktadır.","2":"Kurumda kalite güvencesi kültürünü destekleyen kurumsal kültür ve liderlik yaklaşımı oluşturmak üzere planlar bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları ve birimleri kapsamayan uygulamalar bulunmaktadır.","3":"Kurumda kalite güvencesi kültürünü destekleyen, tüm birimleri ve süreçleri kapsayan kurumsal kültür ve liderlik anlayışı bulunmakta olup; bu kapsamda gerçekleştirilen faaliyetlerden bazı sonuçlar elde edilmiştir. Ancak tüm bu uygulamalar kurumdaki bütüncül kalite yönetimi kapsamında yürütülmemekte ve bu uygulamaların sonuçları izlenmemektedir.","4":"Kurumda yüksek kaliteyi kalıcı bir şekilde sağlayan kurumsal kültür ile kurumdaki değer ve beklentiler doğrultusunda kalite çalışmalarının koordine edilmesini sağlayan ve kalite süreçlerini sahiplenen liderlik anlayışı bulunmaktadır. Liderlik ve kalite güvencesi kültürü, kurumdaki bütüncül kalite yönetimi kapsamında izlenmekte, paydaşlarla birlikte değerlendirilmekte ve izlem sonuçlarına göre önlem alınmaktadır.","5":"Tüm birimleri ve süreçleri kapsayan, kurumsal amaçlar doğrultusunda, sürdürülebilir ve olgunlaşmış kurumsal kalite kültürü ve liderlik yaklaşımı kurumun tamamında benimsenmiştir; kurumun kalite kültürünü güçlendirme ve liderlik yaklaşımı kapsamında yenilikçi uygulamaları bulunmakta, uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no corporate culture and leadership approach that supports the culture of quality assurance in the institution.","2":"There are plans to create a corporate culture and leadership approach that supports a culture of quality assurance in the institution. However, there are no applications made in line with these plans, or there are applications that do not cover all areas and units.","3":"The institution has a corporate culture and leadership approach that supports the culture of quality assurance and covers all units and processes; Some results were obtained from the activities carried out in this context. However, all these practices are not carried out within the scope of holistic quality management in the institution and the results of these practices are not monitored.","4":"There is a corporate culture that ensures permanent high quality in the institution, and a leadership approach that ensures the coordination of quality studies in line with the values ​​and expectations in the institution and embraces quality processes. Leadership and quality assurance culture is monitored within the scope of holistic quality management in the institution, evaluated together with stakeholders, and measures are taken according to the monitoring results.","5":"A sustainable and mature corporate quality culture and leadership approach, covering all units and processes, in line with corporate objectives, has been adopted throughout the institution; The institution has innovative practices within the scope of strengthening its quality culture and leadership approach, and some of the practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد ثقافة مؤسسية ونهج قيادي يدعم ثقافة ضمان الجودة في المؤسسة.","2":"هناك خطط لخلق ثقافة مؤسسية ونهج قيادي يدعم ثقافة ضمان الجودة في المؤسسة. ولكن لا يوجد أي طلبات تتماشى مع هذه المخططات، أو هناك طلبات لا تغطي جميع المناطق والوحدات.","3":"تتمتع المؤسسة بثقافة مؤسسية ونهج قيادي يدعم ثقافة ضمان الجودة ويغطي جميع الوحدات والعمليات؛ وتم الحصول على بعض النتائج من الأنشطة التي تم تنفيذها في هذا السياق. إلا أن جميع هذه الممارسات لا يتم تنفيذها ضمن نطاق إدارة الجودة الشاملة في المؤسسة ولا يتم مراقبة نتائج هذه الممارسات.","4":"هناك ثقافة مؤسسية تضمن الجودة العالية الدائمة في المؤسسة، ونهج قيادي يضمن تنسيق دراسات الجودة بما يتماشى مع القيم والتوقعات في المؤسسة ويحتضن عمليات الجودة. تتم مراقبة ثقافة القيادة وضمان الجودة ضمن نطاق إدارة الجودة الشاملة في المؤسسة، ويتم تقييمها مع أصحاب المصلحة، ويتم اتخاذ التدابير وفقًا لنتائج المراقبة.","5":"تم اعتماد نهج مستدام وناضج لثقافة الجودة المؤسسية والقيادة، يغطي جميع الوحدات والعمليات، بما يتماشى مع أهداف الشركة، في جميع أنحاء المؤسسة؛ تمتلك المؤسسة ممارسات مبتكرة في نطاق تعزيز ثقافة الجودة ونهجها القيادي، ويتم أخذ بعض الممارسات كمثال من قبل المؤسسات الأخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (12, 'A.3.1', 'İç Paydaşlar (Çalışanlar - Akademik ve İdari Personel)', 'Internal Stakeholders (Employees - Academic and Administrative Staff)', 'أصحاب المصلحة الداخليون (الموظفون - أعضاء هيئة التدريس والإداريون)', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda yürütülen tüm süreçlere (kalite güvencesi, eğitim ve öğretim, araştırma ve geliştirme, toplumsal katkı, yönetim sistemi, uluslararasılaşma) paydaş katılımını sağlayacak mekanizma ve uygulamalar bulunmamaktadır.","2":"Kurumda paydaşlar belirlenmiş ve paydaş analizleri gerçekleştirilmiştir ve paydaş katılımına ilişkin bazı tanımlı süreçler bulunmaktadır. Ancak bu süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya mevcut uygulamalar bütün süreçleri/alanları/paydaş gruplarını kapsamamaktadır.","3":"Kurumda yürütülen tüm süreçlerle ilişkili olarak belirlenmiş olan paydaşların süreçlere ve karar alma mekanizmalarına katılımı sağlanmıştır ve bu etkileşimden bazı uygulama sonuçları elde edilmiştir. Ancak tüm bu uygulamalar kurumdaki bütüncül kalite yönetimi kapsamında yürütülmemektedir ve bu uygulamaların sonuçları izlenmemektedir.","4":"Kurumdaki tüm süreçlere ve karar almalara paydaşların katılımı kurumdaki bütüncül kalite yönetimi kapsamında yürütülmekte ve paydaş katılımı uygulamalarından elde edilen bulgular izlenerek paydaşlarla birlikte değerlendirilmekte ve izlem sonuçlarına göre önlem alınmaktadır.","5":"Kurumdaki tüm süreçlere ve karar almalara paydaşların katılımı, olgunlaşmış ve sürdürülebilir uygulamalarla sağlanarak kurumun tamamında benimsenmiştir; kurumun paydaş katılımını güçlendirmek üzere yenilikçi uygulamaları bulunmakta, uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no mechanisms and practices that will ensure stakeholder participation in all processes carried out in the institution (quality assurance, education and training, research and development, social contribution, management system, internationalization).","2":"Stakeholders have been identified and stakeholder analyzes have been carried out in the institution, and there are some defined processes for stakeholder participation. However, there are no practices made in line with these processes, or existing practices do not cover all processes/areas/stakeholder groups.","3":"The participation of stakeholders identified in relation to all processes carried out in the institution in the processes and decision-making mechanisms was ensured, and some implementation results were obtained from this interaction. However, all these practices are not carried out within the scope of holistic quality management in the institution and the results of these practices are not monitored.","4":"Participation of stakeholders in all processes and decision-making in the institution is carried out within the scope of holistic quality management in the institution, and the findings obtained from stakeholder participation practices are monitored and evaluated together with the stakeholders and precautions are taken according to the monitoring results.","5":"Participation of stakeholders in all processes and decision-making in the institution is ensured through mature and sustainable practices and adopted throughout the institution; The institution has innovative practices to strengthen stakeholder participation, and some of the practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد آليات وممارسات تضمن مشاركة أصحاب المصلحة في جميع العمليات التي تتم في المؤسسة (ضمان الجودة، التعليم والتدريب، البحث والتطوير، المساهمة الاجتماعية، نظام الإدارة، التدويل).","2":"لقد تم تحديد أصحاب المصلحة وتم إجراء تحليلات لأصحاب المصلحة في المؤسسة، وهناك بعض العمليات المحددة لمشاركة أصحاب المصلحة. ومع ذلك، لا توجد ممارسات تتماشى مع هذه العمليات، أو أن الممارسات الحالية لا تغطي جميع العمليات/المجالات/مجموعات أصحاب المصلحة.","3":"تم ضمان مشاركة أصحاب المصلحة الذين تم تحديدهم فيما يتعلق بجميع العمليات التي تتم في المؤسسة في العمليات وآليات اتخاذ القرار، وتم الحصول على بعض نتائج التنفيذ من هذا التفاعل. إلا أن جميع هذه الممارسات لا يتم تنفيذها ضمن نطاق إدارة الجودة الشاملة في المؤسسة ولا يتم مراقبة نتائج هذه الممارسات.","4":"تتم مشاركة أصحاب المصلحة في جميع العمليات وصنع القرار في المؤسسة ضمن نطاق إدارة الجودة الشاملة في المؤسسة، ويتم رصد وتقييم النتائج التي تم الحصول عليها من ممارسات مشاركة أصحاب المصلحة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة وفقًا لنتائج المراقبة.","5":"يتم ضمان مشاركة أصحاب المصلحة في جميع العمليات وصنع القرار في المؤسسة من خلال ممارسات ناضجة ومستدامة ومعتمدة في جميع أنحاء المؤسسة؛ لدى المؤسسة ممارسات مبتكرة لتعزيز مشاركة أصحاب المصلحة، ويتم أخذ بعض الممارسات كمثال من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (13, 'A.3.2', 'Dış Paydaşlar', 'External Stakeholders', 'أصحاب المصلحة الخارجيين', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda yürütülen tüm süreçlere (kalite güvencesi, eğitim ve öğretim, araştırma ve geliştirme, toplumsal katkı, yönetim sistemi, uluslararasılaşma) paydaş katılımını sağlayacak mekanizma ve uygulamalar bulunmamaktadır.","2":"Kurumda paydaşlar belirlenmiş ve paydaş analizleri gerçekleştirilmiştir ve paydaş katılımına ilişkin bazı tanımlı süreçler bulunmaktadır. Ancak bu süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya mevcut uygulamalar bütün süreçleri/alanları/paydaş gruplarını kapsamamaktadır.","3":"Kurumda yürütülen tüm süreçlerle ilişkili olarak belirlenmiş olan paydaşların süreçlere ve karar alma mekanizmalarına katılımı sağlanmıştır ve bu etkileşimden bazı uygulama sonuçları elde edilmiştir. Ancak tüm bu uygulamalar kurumdaki bütüncül kalite yönetimi kapsamında yürütülmemektedir ve bu uygulamaların sonuçları izlenmemektedir.","4":"Kurumdaki tüm süreçlere ve karar almalara paydaşların katılımı kurumdaki bütüncül kalite yönetimi kapsamında yürütülmekte ve paydaş katılımı uygulamalarından elde edilen bulgular izlenerek paydaşlarla birlikte değerlendirilmekte ve izlem sonuçlarına göre önlem alınmaktadır.","5":"Kurumdaki tüm süreçlere ve karar almalara paydaşların katılımı, olgunlaşmış ve sürdürülebilir uygulamalarla sağlanarak kurumun tamamında benimsenmiştir; kurumun paydaş katılımını güçlendirmek üzere yenilikçi uygulamaları bulunmakta, uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no mechanisms and practices that will ensure stakeholder participation in all processes carried out in the institution (quality assurance, education and training, research and development, social contribution, management system, internationalization).","2":"Stakeholders have been identified and stakeholder analyzes have been carried out in the institution, and there are some defined processes for stakeholder participation. However, there are no practices made in line with these processes, or existing practices do not cover all processes/areas/stakeholder groups.","3":"The participation of stakeholders identified in relation to all processes carried out in the institution in the processes and decision-making mechanisms was ensured, and some implementation results were obtained from this interaction. However, all these practices are not carried out within the scope of holistic quality management in the institution and the results of these practices are not monitored.","4":"Participation of stakeholders in all processes and decision-making in the institution is carried out within the scope of holistic quality management in the institution, and the findings obtained from stakeholder participation practices are monitored and evaluated together with the stakeholders and precautions are taken according to the monitoring results.","5":"Participation of stakeholders in all processes and decision-making in the institution is ensured through mature and sustainable practices and adopted throughout the institution; The institution has innovative practices to strengthen stakeholder participation, and some of the practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد آليات وممارسات تضمن مشاركة أصحاب المصلحة في جميع العمليات التي تتم في المؤسسة (ضمان الجودة، التعليم والتدريب، البحث والتطوير، المساهمة الاجتماعية، نظام الإدارة، التدويل).","2":"لقد تم تحديد أصحاب المصلحة وتم إجراء تحليلات لأصحاب المصلحة في المؤسسة، وهناك بعض العمليات المحددة لمشاركة أصحاب المصلحة. ومع ذلك، لا توجد ممارسات تتماشى مع هذه العمليات، أو أن الممارسات الحالية لا تغطي جميع العمليات/المجالات/مجموعات أصحاب المصلحة.","3":"تم ضمان مشاركة أصحاب المصلحة الذين تم تحديدهم فيما يتعلق بجميع العمليات التي تتم في المؤسسة في العمليات وآليات اتخاذ القرار، وتم الحصول على بعض نتائج التنفيذ من هذا التفاعل. إلا أن جميع هذه الممارسات لا يتم تنفيذها ضمن نطاق إدارة الجودة الشاملة في المؤسسة ولا يتم مراقبة نتائج هذه الممارسات.","4":"تتم مشاركة أصحاب المصلحة في جميع العمليات وصنع القرار في المؤسسة ضمن نطاق إدارة الجودة الشاملة في المؤسسة، ويتم رصد وتقييم النتائج التي تم الحصول عليها من ممارسات مشاركة أصحاب المصلحة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة وفقًا لنتائج المراقبة.","5":"يتم ضمان مشاركة أصحاب المصلحة في جميع العمليات وصنع القرار في المؤسسة من خلال ممارسات ناضجة ومستدامة ومعتمدة في جميع أنحاء المؤسسة؛ لدى المؤسسة ممارسات مبتكرة لتعزيز مشاركة أصحاب المصلحة، ويتم أخذ بعض الممارسات كمثال من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (14, 'A.4.1', 'Uluslararasılaşma Politikası', 'Internationalization Policy', 'سياسة التدويل', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda tanımlı bir uluslararasılaşma politikası bulunmamaktadır.","2":"Kurumun tanımlı uluslararasılaşma politikası bulunmaktadır. Ancak bu politika doğrultusunda gerçekleştirilmiş uygulamalar bulunmamaktadır.","3":"Kurumun eğitim ve öğretim, araştırma ve geliştirme ve toplumsal katkı fonksiyonlarının tümünü dikkate alan uluslararasılaşma politikası doğrultusunda bazı uygulamaları bulunmaktadır ve bu uygulamalardan bazı sonuçlar elde edilmiştir. Ancak bu uygulamaların sonuçları izlenmemektedir.","4":"Kurumun uluslararasılaşma politikası doğrultusunda yapılan uygulamalar sistematik ve kurumun iç kalite güvencesi sistemi ile uyumlu olarak izlenmekte ve paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumun özgün uluslararasılaşma modeli kurumun tamamında benimsenmiştir; kurumun uluslararasılaşma modeli kapsamında yenilikçi uygulamalar bulunmakta, uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no defined internationalization policy in the institution.","2":"The institution has a defined internationalization policy. However, there are no practices implemented in line with this policy.","3":"The institution has some practices in line with its internationalization policy, which takes into account all education and training, research and development and social contribution functions, and some results have been obtained from these practices. However, the results of these practices are not monitored.","4":"Practices carried out in line with the institution''s internationalization policy are monitored systematically and in accordance with the institution''s internal quality assurance system, and measures are taken by evaluating them together with stakeholders.","5":"The institution''s unique internationalization model is adopted throughout the institution; There are innovative practices within the scope of the institution''s internationalization model, and some of the practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد سياسة تدويل محددة في المؤسسة.","2":"المؤسسة لديها سياسة تدويل محددة. ومع ذلك، لا توجد ممارسات يتم تنفيذها بما يتماشى مع هذه السياسة.","3":"لدى المؤسسة بعض الممارسات التي تتماشى مع سياسة التدويل الخاصة بها، والتي تأخذ في الاعتبار جميع وظائف التعليم والتدريب والبحث والتطوير والمساهمة الاجتماعية، وقد تم الحصول على بعض النتائج من هذه الممارسات. ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"تتم مراقبة الممارسات التي تتم بما يتماشى مع سياسة التدويل الخاصة بالمؤسسة بشكل منهجي ووفقًا لنظام ضمان الجودة الداخلي للمؤسسة، ويتم اتخاذ التدابير من خلال تقييمها مع أصحاب المصلحة.","5":"يتم اعتماد نموذج التدويل الفريد للمؤسسة في جميع أنحاء المؤسسة؛ هناك ممارسات مبتكرة ضمن نطاق نموذج التدويل الخاص بالمؤسسة، ويتم أخذ بعض الممارسات كمثال من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (15, 'A.4.2', 'Uluslararasılaşma Süreçlerinin Yönetimi ve Organizasyonel Yapısı', 'Management and Organizational Structure of Internationalization Processes', 'الإدارة والهيكل التنظيمي لعمليات التدويل', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun uluslararasılaşma süreçlerinin yönetimi ve organizasyonel yapısına ilişkin planlamalar bulunmamaktadır.","2":"Kurumun uluslararasılaşma süreçlerinin yönetim ve organizasyonel yapısına ilişkin planlamalar bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır.","3":"Kurumda uluslararasılaşma süreçlerinin yönetimi ve organizasyonel yapısı kurumsal tercihler yönünde uygulamaya konularak bazı sonuçlar elde edilmiştir. Ancak bu sonuçlar izlenmemektedir.","4":"Kurumda uluslararasılaşma süreçlerinin yönetimi ile ilişkili sonuçlar ve paydaş görüşleri sistematik olarak izlenmekte ve paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda tüm birimleri/alanları kapsayan uluslararasılaşma yönetimi, kurumsal amaçlar doğrultusunda bütünleştirici, sürdürülebilir ve olgunlaşmış uygulamalarla kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no plans regarding the management and organizational structure of the institution''s internationalization processes.","2":"There are plans regarding the management and organizational structure of the institution''s internationalization processes. However, there are no practices made in line with these plans.","3":"Some results have been achieved by implementing the management and organizational structure of internationalization processes in the institution in line with institutional preferences. However, these results are not monitored.","4":"The results and stakeholder opinions related to the management of internationalization processes in the institution are systematically monitored and measures are taken by evaluating them together with the stakeholders.","5":"Internationalization management, covering all units/areas in the institution, has been adopted and secured throughout the institution with integrative, sustainable and mature practices in line with corporate objectives; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد خطط فيما يتعلق بالإدارة والهيكل التنظيمي لعمليات تدويل المؤسسة.","2":"هناك خطط تتعلق بالإدارة والهيكل التنظيمي لعمليات تدويل المؤسسة. ومع ذلك، لا توجد ممارسات تتماشى مع هذه الخطط.","3":"وقد تم تحقيق بعض النتائج من خلال تنفيذ الهيكل الإداري والتنظيمي لعمليات التدويل في المؤسسة بما يتماشى مع التفضيلات المؤسسية. ومع ذلك، لا يتم رصد هذه النتائج.","4":"تتم مراقبة النتائج وآراء أصحاب المصلحة المتعلقة بإدارة عمليات التدويل في المؤسسة بشكل منهجي ويتم اتخاذ التدابير من خلال تقييمها مع أصحاب المصلحة.","5":"تم اعتماد إدارة التدويل، التي تغطي جميع الوحدات/المجالات في المؤسسة، وتأمينها في جميع أنحاء المؤسسة بممارسات متكاملة ومستدامة وناضجة بما يتماشى مع أهداف الشركة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (16, 'A.4.3', 'Uluslararasılaşma Kaynakları', 'Internationalization Resources', 'موارد التدويل', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun uluslararasılaşma faaliyetlerini sürdürebilmesi için uygun nitelik ve nicelikte fiziki, teknik ve mali kaynakları bulunmamaktadır.","2":"Kurumun uluslararasılaşma faaliyetlerini sürdürebilmek için uygun nitelik ve nicelikte fiziki, teknik ve mali kaynakların oluşturulmasına yönelik planlar bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır .","3":"Kurumun uluslararasılaşma faaliyetlerini sürdürebilmek için uygun nitelik ve nicelikte fiziki, teknik ve mali kaynaklar sağlanmaktadır. Ancak bu kaynakların kullanımına yönelik sonuçlar izlenmemektedir.","4":"Kurumda fiziki, teknik ve mali kaynaklar, uluslararasılaşma faaliyetlerini destekleyecek şekilde yönetilmektedir. Tüm bu uygulamalardan elde edilen bulgular, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar/talepler doğrultusunda kaynaklar çeşitlendirilmektedir.","5":"Kurumda uygun nicelik ve nitelikte fiziki, teknik ve mali kaynaklar, kurumsal amaçlar (uluslararasılaşma politikası ve stratejisi) doğrultusunda ve sürdürülebilir şekilde yönetilmektedir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have physical, technical and financial resources of appropriate quality and quantity to continue its internationalization activities.","2":"There are plans to create physical, technical and financial resources of appropriate quality and quantity in order to continue the internationalization activities of the institution. However, there are no practices made in line with these plans.","3":"Physical, technical and financial resources of appropriate quality and quantity are provided in order to continue the internationalization activities of the institution. However, the results of the use of these resources are not monitored.","4":"The institution''s physical, technical and financial resources are managed to support internationalization activities. The findings obtained from all these applications are systematically monitored and the monitoring results are evaluated together with the stakeholders, precautions are taken and resources are diversified in line with the needs/demands.","5":"In the institution, physical, technical and financial resources of appropriate quantity and quality are managed in a sustainable manner in line with corporate objectives (internationalization policy and strategy); The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا تمتلك المؤسسة الموارد المادية والتقنية والمالية ذات الجودة والكمية المناسبة لمواصلة أنشطتها الدولية.","2":"هناك خطط لإنشاء موارد مادية وتقنية ومالية ذات نوعية وكمية مناسبة من أجل مواصلة أنشطة تدويل المؤسسة. ومع ذلك، لا توجد ممارسات تتماشى مع هذه الخطط.","3":"يتم توفير الموارد المادية والتقنية والمالية ذات الجودة والكمية المناسبة من أجل مواصلة أنشطة تدويل المؤسسة. ومع ذلك، لا يتم رصد نتائج استخدام هذه الموارد.","4":"تتم إدارة الموارد المادية والتقنية والمالية للمؤسسة لدعم أنشطة التدويل. تتم مراقبة النتائج التي تم الحصول عليها من جميع هذه التطبيقات بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة، ويتم اتخاذ الاحتياطات وتنويع الموارد بما يتماشى مع الاحتياجات / المتطلبات.","5":"في المؤسسة، تتم إدارة الموارد المادية والتقنية والمالية ذات الكمية والنوعية المناسبة بطريقة مستدامة بما يتماشى مع أهداف الشركة (سياسة واستراتيجية التدويل)؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (17, 'A.4.4', 'Uluslararasılaşma Performansının İzlenmesi ve İyileştirilmesi', 'Monitoring and Improving Internationalization Performance', 'مراقبة وتحسين أداء التدويل', 1, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda uluslararasılaşma performansının izlenmesine ve değerlendirmesine yönelik planlamalar ve tanımlı süreçler bulunmamaktadır.","2":"Kurumda uluslararasılaşma performansının izlenmesine ve değerlendirmesine yönelik planlamalar ve tanımlı süreçler bulunmaktadır. Ancak bu planlar ve süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır.","3":"Kurumda uluslararasılaşma performansının izlenmesine ve değerlendirmesine yönelik uygulamalar tüm alanları kapsar şekilde yürütülmektedir. Ancak bu uygulamaların sonuçları izlenmemektedir veya karar alma süreçlerinde kullanılmamaktadır.","4":"Kurumda uluslararasılaşma hedefleri doğrultusunda çalışma yapan birimlerin(Komisyon, koordinatörlük, iş birliği yapılan merkez vb.) uluslararasılaşma performansı izlenerek değerlendirilmekte ve karar alma süreçlerinde kullanılmaktadır. Buna ilişkin uygulamalar düzenli olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda, kurumsal amaçlar (uluslararasılaşma politikası, hedefleri, stratejisi) ve uluslararasılaşma hedefleri doğrultusunda çalışma yapan birimlerin uluslararasılaşma performansının izlenmesi ve değerlendirilmesine ilişkin sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiş ve güvence altına alınmıştır. Kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no plans or defined processes for monitoring and evaluating internationalization performance in the institution.","2":"The institution has plans and defined processes for monitoring and evaluating internationalization performance. However, there are no practices made in line with these plans and processes.","3":"Practices for monitoring and evaluating internationalization performance in the institution are carried out in a way that covers all areas. However, the results of these practices are not monitored or used in decision-making processes.","4":"The internationalization performance of the units (Commission, coordinatorship, cooperating center, etc.) working in line with the internationalization targets in the institution is monitored and evaluated and used in decision-making processes. Related practices are monitored regularly and the monitoring results are evaluated together with stakeholders and precautions are taken.","5":"In the institution, sustainable and mature practices regarding the monitoring and evaluation of the internationalization performance of the units working in line with the institutional goals (internationalization policy, goals, strategy) and internationalization targets have been adopted and secured throughout the institution. The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد خطط أو عمليات محددة لرصد وتقييم أداء التدويل في المؤسسة.","2":"لدى المؤسسة خطط وعمليات محددة لرصد وتقييم أداء التدويل. ومع ذلك، لا توجد ممارسات تتماشى مع هذه الخطط والعمليات.","3":"يتم تنفيذ ممارسات مراقبة وتقييم أداء التدويل في المؤسسة بطريقة تغطي جميع المجالات. ومع ذلك، لا يتم رصد نتائج هذه الممارسات أو استخدامها في عمليات صنع القرار.","4":"تتم مراقبة وتقييم أداء التدويل للوحدات (اللجنة، التنسيق، المركز المتعاون، إلخ) التي تعمل بما يتماشى مع أهداف التدويل في المؤسسة، واستخدامه في عمليات صنع القرار. تتم مراقبة الممارسات ذات الصلة بانتظام ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"في المؤسسة، تم اعتماد وتأمين ممارسات مستدامة وناضجة فيما يتعلق برصد وتقييم أداء التدويل للوحدات العاملة بما يتماشى مع الأهداف المؤسسية (سياسة التدويل، والأهداف، والاستراتيجية) وأهداف التدويل في جميع أنحاء المؤسسة. تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (18, 'B.1.1', 'Program Tasarım ve Onayı', 'Program Design and Approval', 'تصميم البرنامج والموافقة عليه', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda programın tasarımı ve onayına ilişkin tanımlı ve sistematik süreçler bulunmamaktadır.","2":"Kurumda programın tasar ımı ve onayına ilişkin tanımlı ve sistematik süreçler bulunmaktadır. Ancak bu süreçler tüm alanları kapsamamaktadır.","3":"Kurumda programın tasarımı ve onayına ilişkin tanımlı süreçler doğrultusunda uygulamalar gerçekleştirilmiş ve bu uygulamalardan bazı sonuçlar elde edilmiştir. Ancak bu uygulamaların sonuçlarının izlenmesi yapılmamaktadır.","4":"Paydaşların katılımıyla programın tasarımı ve onayına ilişkin uygulamalar sistematik olarak izlenmekte ve paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Paydaşların katılımıyla programın tasarımı ve onayına ilişkin sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiştir; bu kapsamda kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmaktadır ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no defined and systematic processes in the institution regarding the design and approval of the program.","2":"The institution has defined and systematic processes for program design and approval. However, these processes do not cover all areas.","3":"Applications have been carried out in line with the defined processes regarding the design and approval of the program in the institution, and some results have been obtained from these applications. However, the results of these practices are not monitored.","4":"With the participation of stakeholders, practices regarding the design and approval of the program are systematically monitored and measures are taken by evaluating them together with the stakeholders.","5":"Sustainable and mature practices for program design and approval with stakeholder participation are adopted throughout the institution; In this context, the institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد عمليات محددة ومنهجية في المؤسسة فيما يتعلق بتصميم البرنامج والموافقة عليه.","2":"لدى المؤسسة عمليات محددة ومنهجية لتصميم البرامج والموافقة عليها. إلا أن هذه العمليات لا تغطي جميع المجالات.","3":"تم تنفيذ الطلبات بما يتماشى مع العمليات المحددة فيما يتعلق بتصميم البرنامج والموافقة عليه في المؤسسة، وتم الحصول على بعض النتائج من هذه التطبيقات. ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"وبمشاركة أصحاب المصلحة، تتم مراقبة الممارسات المتعلقة بتصميم البرنامج والموافقة عليه بشكل منهجي ويتم اتخاذ التدابير من خلال تقييمها مع أصحاب المصلحة.","5":"يتم اعتماد ممارسات مستدامة وناضجة لتصميم البرامج والموافقة عليها بمشاركة أصحاب المصلحة في جميع أنحاء المؤسسة؛ وفي هذا السياق، تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (19, 'B.1.2', 'Program Amaçları, Çıktıları ve İAA Ölçütleri ile Uyumu', 'Program Objectives, Outputs and Compatibility with IAA Criteria', 'أهداف البرنامج ومخرجاته وتوافقه مع معايير IAA', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumdaki programın amaçları, çıktıları ve bunların İAA ölçütleri ile uyumları tanımlanmamıştır.","2":"Kurumdaki programın amaçları , çıktıları ve bunların İAA ölçütleri ile uyumları tanımlanmıştır. Ancak bu uygulama tüm alanlarda gerçekleştirilmemektedir.","3":"Kurumdaki programın amaçları , çıktıları ve bunların İAA ölçütleri ile uyumları tanımlanmış, ilan edilmiştir ve eğitim öğretimle ilgili uygulamalarla ilişkilendirilmiştir. Ancak bu uygulamaların sonuçlarının izlenmesi yapılmamaktadır.","4":"Programın amaçları, çıktıları ve bunların İAA ölçütleri ile uyumlarına ilişkin tüm alanları kapsayan uygulamalar, sistematik olarak izlenmekte ve p aydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Programın amaçları, çıktıları ve bunların İAA ölçütleri ile uyumlarına ilişkin sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiştir; bu kapsamda kurumun kendine özgü, yenilikçi ve diğer kurumlar tarafından örnek alınan uygulamaları bulunmaktadır."}'::jsonb, NULL, '{"1":"The objectives and outcomes of the program in the institution and their compliance with IAA criteria are not defined.","2":"The objectives and outputs of the program in the institution and their compliance with IAA criteria are defined. However, this practice is not implemented in all areas.","3":"The aims and outcomes of the program in the institution and their compliance with the IAA criteria are defined, announced and associated with education-related practices. However, the results of these practices are not monitored.","4":"Applications covering all areas regarding the program''s objectives, outputs and their compliance with IAA criteria are systematically monitored and evaluated together with stakeholders and precautions are taken.","5":"Sustainable and mature practices regarding the program''s objectives, outcomes and their compliance with IAA criteria have been adopted throughout the institution; In this context, the institution has unique, innovative practices that are taken as an example by other institutions."}'::jsonb, '{"1":"لم يتم تحديد أهداف ونتائج البرنامج في المؤسسة ومدى امتثالها لمعايير IAA.","2":"يتم تحديد أهداف ومخرجات البرنامج في المؤسسة ومدى مطابقتها لمعايير IAA. ومع ذلك، لا يتم تنفيذ هذه الممارسة في جميع المجالات.","3":"يتم تحديد أهداف ونتائج البرنامج في المؤسسة وامتثالها لمعايير IAA، والإعلان عنها وربطها بالممارسات المتعلقة بالتعليم. ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"تتم مراقبة وتقييم الطلبات التي تغطي جميع المجالات المتعلقة بأهداف البرنامج ومخرجاته وامتثالها لمعايير IAA بشكل منهجي مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تم اعتماد ممارسات مستدامة وناضجة فيما يتعلق بأهداف البرنامج ونتائجه وامتثالها لمعايير IAA في جميع أنحاء المؤسسة؛ وفي هذا السياق، تتمتع المؤسسة بممارسات فريدة ومبتكرة تقتدي بها المؤسسات الأخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (20, 'B.1.3', 'Ders Kazanımlarının Program Çıktıları ve Disipline Özgü Çıktılar ile Eşleştirilmesi', 'Matching Course Outcomes with Program Outcomes and Discipline-Specific Outcomes', 'مطابقة نتائج الدورة مع نتائج البرنامج والنتائج الخاصة بالانضباط', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Programda, ders kazanımları ile program çıktıları ve disipline özgü çıktılar eşleştirilmemiştir.","2":"Programda ders kazanımları ile program çıktıları ve disipline özgü çıktılar eşleştirilmiştir.","3":"Programda dersin bilişsel seviyesini (Bloom seviyesini) açıkça belirten ders kazanımları ile program çıktıları ve disipline özgü çıktılar eşleştirilmiş ve bu eşleştirme ilan edilerek, eğitim -öğretimle ilgili uygulamalara (ders profilleri ve izlenceler gibi) yansıtıl mıştır. Ancak bu uygulamaların sonuçlarının izlenmesi yapılmamaktadır.","4":"Programın ders kazanımları ile program çıktıları ve disipline özgü çıktıların eşleştirilmesine ilişkin tüm alanları kapsayan uygulamalar, sistematik olarak ve kurumun iç kalite güvence si sistemiyle uyumlu olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlem alınmaktadır.","5":"Ders kazanımları ile program çıktıları ve disipline özgü çıktılar açık, anlaşılır, gerçekçi ve sürdürülebilir şekilde eşleştirilmiş ve tüm alanlarda içselleştirilmiştir; bu kapsamda kuruma özgü, yenilikçi ve diğer kurumlar tarafından örnek alınan uygulamalar bulunmaktadır."}'::jsonb, NULL, '{"1":"In the program, course outcomes are not matched with program outcomes and discipline-specific outcomes.","2":"In the program, course outcomes are matched with program outcomes and discipline-specific outcomes.","3":"In the program, course outcomes that clearly indicate the cognitive level (Bloom level) of the course were matched with program outcomes and discipline-specific outcomes, and this matching was declared and reflected in education-related practices (such as course profiles and syllabuses). However, the results of these practices are not monitored.","4":"Practices covering all areas related to matching course outcomes of the program with program outcomes and discipline-specific outcomes are monitored systematically and in accordance with the institution''s internal quality assurance system, and the monitoring results are evaluated together with stakeholders and precautions are taken.","5":"Course outcomes, program outcomes and discipline-specific outcomes are matched in a clear, understandable, realistic and sustainable manner and are internalized in all areas; In this context, there are institution-specific, innovative practices that are taken as an example by other institutions."}'::jsonb, '{"1":"في البرنامج، لا تتطابق نتائج الدورة مع نتائج البرنامج والنتائج الخاصة بالتخصص.","2":"في البرنامج، تتم مطابقة نتائج الدورة مع نتائج البرنامج والنتائج الخاصة بالتخصص.","3":"في البرنامج، تمت مطابقة نتائج الدورة التي تشير بوضوح إلى المستوى المعرفي (مستوى بلوم) للدورة مع نتائج البرنامج والنتائج الخاصة بالتخصص، وتم الإعلان عن هذه المطابقة وانعكست في الممارسات المتعلقة بالتعليم (مثل ملفات الدورة والمناهج الدراسية). ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"تتم مراقبة الممارسات التي تغطي جميع المجالات المتعلقة بمطابقة نتائج المقرر الدراسي للبرنامج مع نتائج البرنامج والنتائج الخاصة بالتخصص بشكل منهجي ووفقًا لنظام ضمان الجودة الداخلي للمؤسسة، ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تتم مطابقة نتائج الدورة ونتائج البرنامج والنتائج الخاصة بالانضباط بطريقة واضحة ومفهومة وواقعية ومستدامة ويتم استيعابها في جميع المجالات؛ وفي هذا السياق، هناك ممارسات مبتكرة خاصة بمؤسسات معينة، والتي تتخذها المؤسسات الأخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (21, 'B.1.4', 'Programın Yapısı ve Ders Dağılım Dengesi', 'Structure of the Program and Course Distribution Balance', 'هيكل البرنامج وتوازن توزيع الدورة', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Programın yapısı ve ders dağılım dengesi programda hiçbir alanda dikkate alınmamıştır.","2":"Programın yapısı ve ders dağılım dengesine ilişkin planlamalar bulunmaktadır. Ancak bu uygulamalar tüm alanları kapsamamaktadır.","3":"Programda program ve ders bilgi paketleri, yapı ve ders dağılım dengesi (alan ve meslek bilgisi ile genel kültür dersleri dengesi, kültürel derinlik kazanma, farklı disiplinleri tanıma imkânları vb.) gözetilerek hazırlanmıştır. Ancak bu uygulamaların sonuçlarının izlenmesi yapılmamaktadır.","4":"Program yapısı ve dengesine ilişkin uygulamalar tüm alanlarda, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlem alınmakta ve sürekli olarak güncellenmektedir.","5":"Program yapısı ve dengesine ilişkin kurumsal amaçlar (eğitim-öğretim politikası) doğrultusunda, sürdürülebilir ve olgunlaşmış uygulamalar tüm birimlerde benimsenmiştir. Kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The structure of the program and the balance of course distribution are not taken into consideration in any area of ​​the program.","2":"There are plans regarding the structure of the program and the balance of course distribution. However, these applications do not cover all areas.","3":"The program and course information packages in the program have been prepared by taking into account the balance of structure and course distribution (balance of field and professional knowledge and general culture courses, gaining cultural depth, opportunities to get to know different disciplines, etc.). However, the results of these practices are not monitored.","4":"Practices regarding program structure and balance are monitored systematically in all areas, and the monitoring results are evaluated together with stakeholders, precautions are taken and constantly updated.","5":"In line with institutional goals (education-training policy) regarding program structure and balance, sustainable and mature practices have been adopted in all units. The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا يؤخذ بعين الاعتبار هيكل البرنامج وتوازن توزيع المقررات في أي مجال من مجالات البرنامج.","2":"هناك خطط تتعلق بهيكل البرنامج وتوازن توزيع الدورات. ومع ذلك، فإن هذه التطبيقات لا تغطي جميع المجالات.","3":"تم إعداد الحزم المعلوماتية الخاصة بالبرامج والمقررات في البرنامج مع مراعاة التوازن في الهيكلية وتوزيع المقررات (توازن المعرفة الميدانية والمهنية ودورات الثقافة العامة، اكتساب العمق الثقافي، فرص التعرف على التخصصات المختلفة، وما إلى ذلك). ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"تتم مراقبة الممارسات المتعلقة بهيكل البرنامج وتوازنه بشكل منهجي في جميع المجالات، ويتم تقييم نتائج المراقبة مع أصحاب المصلحة، ويتم اتخاذ الاحتياطات اللازمة وتحديثها باستمرار.","5":"وتمشيا مع الأهداف المؤسسية (سياسة التعليم والتدريب) فيما يتعلق بهيكل البرنامج والتوازن، تم اعتماد ممارسات مستدامة وناضجة في جميع الوحدات. تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (22, 'B.1.5', 'Öğrenci İş Yüküne Dayalı Tasarım', 'Design Based on Student Workload', 'التصميم على أساس عبء العمل الطالب', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Programda öğrenci iş yüküne dayalı tasarım bulunmamaktadır.","2":"Programda öğrenci iş yüküne dayalı tasarım planlamaları bulunmaktadır. Ancak bunlar tüm alanları kapsamamakta veya eğitim ve öğretimle ilgili tüm uygulamalarda kullanılmamaktadır.","3":"Programda tanımlanmış olan öğrenci iş yükleri, paydaşlarla paylaşılmakta (program ve ders bilgi paketleri yoluyla) ve eğitim -öğretimle ilgili tüm uygulamalarda (öğrenci hareketliliği, önceki öğrenmelerin tanınması vb.) kullanılmaktadır. Ancak öğrenci iş yükü ve bununla ilgili uygulamaların sonuçlarının izlenmesi yapılmamaktadır.","4":"Programda uygulanan öğrenci iş yükü uygulaması, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlend irilerek önlemler alınmaktadır.","5":"Öğrenci iş yükü uygulaması, kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde kurumun tamamında benimsenmiştir. Kurumun bu hususta kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no design based on student workload in the program.","2":"The program includes design plans based on student workload. However, these do not cover all areas or are used in all applications related to education and training.","3":"Student workloads defined in the program are shared with stakeholders (through program and course information packages) and used in all education-related applications (student mobility, recognition of previous learning, etc.). However, student workload and the results of related practices are not monitored.","4":"The student workload application implemented in the program is systematically monitored and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"Student workload practice has been adopted throughout the institution in line with institutional goals and in a sustainable manner. The institution has many unique and innovative practices in this regard, and some of these practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا يوجد تصميم يعتمد على حجم عمل الطالب في البرنامج.","2":"ويتضمن البرنامج خطط التصميم على أساس حجم العمل الطالب. ومع ذلك، فهي لا تغطي جميع المجالات أو تستخدم في جميع التطبيقات المتعلقة بالتعليم والتدريب.","3":"تتم مشاركة أعباء عمل الطلاب المحددة في البرنامج مع أصحاب المصلحة (من خلال حزم معلومات البرنامج والدورة التدريبية) واستخدامها في جميع التطبيقات المتعلقة بالتعليم (تنقل الطلاب، والاعتراف بالتعلم السابق، وما إلى ذلك). ومع ذلك، لا تتم مراقبة عبء عمل الطلاب ونتائج الممارسات ذات الصلة.","4":"تتم مراقبة تطبيق عبء عمل الطلاب المطبق في البرنامج بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تم اعتماد ممارسة عبء العمل للطلاب في جميع أنحاء المؤسسة بما يتماشى مع الأهداف المؤسسية وبطريقة مستدامة. ولدى المؤسسة العديد من الممارسات الفريدة والمبتكرة في هذا الصدد، وبعض هذه الممارسات تتخذها مؤسسات أخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (23, 'B.1.6', 'Ölçme ve Değerlendirme', 'Measurement and Evaluation', 'القياس والتقييم', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Programda yeterlilik temelli ölçme ve değerlendirme yaklaşımı bulunmamaktadır.","2":"Programda yeterlilik temelli ölçme ve değerlendirme sisteminin tasarımı bulunmaktadır. Ancak bu tüm alanları kapsamamaktadır.","3":"Programda yeterlilik temelli ölçme ve değerlendirme sisteminin tasarımı tüm alanları kapsamaktadır ve tasarımın uygulanmasından bazı sonuçlar elde edilmiştir. Ancak tasarlanan bu ölçme ve değerlendirme sisteminin sonuçlarının izlenmesi yapılmamaktadır.","4":"Programda tasarlanan ölçme ve değerlendirme sistemine ilişkin uygulamalardan elde edilen bulgular sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Programda kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde tasarlanan ölçme ve değerlendirme sistemi, kurumun tamamında benimsenmiştir. Bu kapsamda kurumun kendine özgü, yenilikçi ve diğer kurumlar tarafından örnek alınan bazı uygulamaları bulunmaktadır."}'::jsonb, NULL, '{"1":"There is no competency-based measurement and evaluation approach in the program.","2":"The program includes the design of a competency-based measurement and evaluation system. However, this does not cover all areas.","3":"The design of the competency-based measurement and evaluation system in the program covers all areas and some results have been obtained from the implementation of the design. However, the results of this designed measurement and evaluation system are not monitored.","4":"The findings obtained from the applications related to the measurement and evaluation system designed in the program are systematically monitored and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"In the program, the measurement and evaluation system designed in line with institutional goals and in a sustainable manner has been adopted throughout the institution. In this context, the institution has some unique, innovative practices that are taken as an example by other institutions."}'::jsonb, '{"1":"لا يوجد نهج للقياس والتقييم على أساس الكفاءة في البرنامج.","2":"ويتضمن البرنامج تصميم نظام القياس والتقييم القائم على الكفاءة. ومع ذلك، فإن هذا لا يشمل جميع المجالات.","3":"يغطي تصميم نظام القياس والتقييم المبني على الكفاءة في البرنامج كافة المجالات وتم الحصول على بعض النتائج من تنفيذ التصميم. ومع ذلك، لا يتم رصد نتائج نظام القياس والتقييم المصمم.","4":"تتم مراقبة النتائج التي تم الحصول عليها من التطبيقات المتعلقة بنظام القياس والتقييم المصمم في البرنامج بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تم في البرنامج اعتماد نظام القياس والتقييم المصمم بما يتماشى مع الأهداف المؤسسية وبطريقة مستدامة في جميع أنحاء المؤسسة. وفي هذا السياق، تمتلك المؤسسة بعض الممارسات الفريدة والمبتكرة التي تتخذها المؤسسات الأخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (24, 'B.2.1', 'Öğrenci Kabulü ve Önceki Öğrenmelerin Tanınması ve Kredilendirilmesi', 'Student Admission and Recognition and Crediting of Prior Learning', 'قبول الطلاب والاعتراف واعتماد التعلم السابق', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda öğrenci kabulü, önceki öğrenmenin tanınması ve kredilendirilmesine ilişkin kriterler ve süreçler tanımlanmamıştır.","2":"Kurumda öğrenci kabulü, önceki öğrenmenin tanınmasına veya kredilendirilmesine ilişkin, yayımlanarak kamuoyu erişimine açılmış tanımlı kriterler ve süreçler vardır. Ancak bu durum ve uygulamalar kurumdaki tüm alanları kapsamamaktadır.","3":"Kurumda öğrenci kabulü, önceki öğrenmenin tanınması ve kredilendirilmesine ilişkin tanımlı kriterler ve süreçler uygulanmaktadır. Ancak bu uygulamaların sonuçlarının izlenmesi yapılmamaktadır.","4":"Öğrenci kabulü, önceki öğrenmenin tanınması ve kredilendirilmesine ilişkin uygulamalardan elde edilen bulgular, sistematik olarak izlenerek paydaşlarla birlikte değerlendirilmekte ve izlem sonuçlarına göre önlem alınmaktadır.","5":"Kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde yürütülen öğrenci kabulü ve önceki öğrenimin tanınması ve kredilendirilmesi uygulamaları kurumun tamamında benimsenmiştir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"Criteria and processes regarding student acceptance, recognition and crediting of prior learning are not defined in the institution.","2":"The institution has defined criteria and processes regarding student admission and recognition or crediting of prior learning, which have been published and made available to the public. However, these situations and practices do not cover all areas in the institution.","3":"Defined criteria and processes regarding student admission, recognition and crediting of prior learning are applied at the institution. However, the results of these practices are not monitored.","4":"Findings obtained from practices regarding student admission, recognition and crediting of prior learning are systematically monitored and evaluated together with stakeholders, and precautions are taken according to the monitoring results.","5":"Student admission and recognition and crediting of prior learning practices, which are carried out in line with institutional goals and in a sustainable manner, have been adopted throughout the institution; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لم يتم تحديد المعايير والعمليات المتعلقة بقبول الطالب والاعتراف به وتسجيل التعلم السابق في المؤسسة.","2":"وقد حددت المؤسسة المعايير والعمليات المتعلقة بقبول الطلاب والاعتراف أو تسجيل التعلم السابق، والتي تم نشرها وإتاحتها للجمهور. إلا أن هذه الأوضاع والممارسات لا تغطي جميع المجالات في المؤسسة.","3":"يتم تطبيق المعايير والعمليات المحددة المتعلقة بقبول الطلاب والاعتراف وتسجيل التعلم السابق في المؤسسة. ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"تتم مراقبة وتقييم النتائج التي تم الحصول عليها من الممارسات المتعلقة بقبول الطلاب والاعتراف وتسجيل التعلم السابق بشكل منهجي مع أصحاب المصلحة، ويتم اتخاذ الاحتياطات اللازمة وفقًا لنتائج المراقبة.","5":"تم اعتماد قبول الطلاب والاعتراف بهم وتسجيل ممارسات التعلم السابقة، والتي يتم تنفيذها بما يتماشى مع الأهداف المؤسسية وبطريقة مستدامة، في جميع أنحاء المؤسسة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (25, 'B.2.2', 'Diploma, Derece ve Diğer Yeterliliklerin Tanınması ve Sertifikalandırılması', 'Recognition and Certification of Diplomas, Degrees and Other Qualifications', 'الاعتراف وإصدار الشهادات للدبلومات والدرجات العلمية والمؤهلات الأخرى', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda diploma, derece ve diğer yeterliliklerin tanınması ve sertifikalandırılması kriterleri ve süreçleri tanımlanmamıştır.","2":"Kurumda diploma, derece ve diğer yeterliliklerin tanınması ve sertifikalandırılmasına ilişkin, yayımlanarak kamuoyu erişimine açılmış tanımlı kriterler ve süreçler vardır.","3":"Diploma, derece ve diğer yeterliliklerin tanınması ve sertifikalandırılmasına ilişkin açık, anlaşılır, kapsamlı ve tutarlı şekilde tanımlanmış kriterler ve süreçler kurumda uygulanmaktadır. Ancak bu uygulamaların sonuçlarının izlenmesi yapılmamaktadır.","4":"Diploma, derece ve diğer yeterliliklerin tanınması ve sertifikalandırılmasına ilişkin uygulamalardan elde edilen bulgular, sistematik olarak izlenerek paydaşlarla birlikte değerlendirilmekte ve izlem sonuçlarına göre önlem alınmaktadır.","5":"Kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde yürütülen diploma, derece ve diğer yeterliliklerin tanınması ve sertifikalandırılmasına ilişkin olgunlaşmış uygulamalar kurumun tamamında benimsenmiştir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The criteria and processes for recognition and certification of diplomas, degrees and other qualifications are not defined in the institution.","2":"The institution has defined criteria and processes regarding the recognition and certification of diplomas, degrees and other qualifications, which are published and made available to the public.","3":"Clear, understandable, comprehensive and consistently defined criteria and processes regarding the recognition and certification of diplomas, degrees and other qualifications are implemented in the institution. However, the results of these practices are not monitored.","4":"Findings obtained from practices regarding the recognition and certification of diplomas, degrees and other qualifications are systematically monitored and evaluated together with stakeholders, and precautions are taken according to the monitoring results.","5":"Mature practices regarding the recognition and certification of diplomas, degrees and other qualifications carried out in line with institutional objectives and in a sustainable manner have been adopted throughout the institution; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لم يتم تحديد معايير وعمليات الاعتراف وإصدار الشهادات للدبلومات والدرجات والمؤهلات الأخرى في المؤسسة.","2":"وقد حددت المؤسسة المعايير والعمليات المتعلقة بالاعتراف والتصديق على الدبلومات والدرجات العلمية والمؤهلات الأخرى، والتي يتم نشرها وإتاحتها للجمهور.","3":"يتم تنفيذ معايير وعمليات واضحة ومفهومة وشاملة ومحددة باستمرار فيما يتعلق بالاعتراف وإصدار الشهادات للدبلومات والدرجات والمؤهلات الأخرى في المؤسسة. ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"تتم مراقبة وتقييم النتائج التي يتم الحصول عليها من الممارسات المتعلقة بالاعتراف والشهادات والشهادات والمؤهلات الأخرى بشكل منهجي مع أصحاب المصلحة، ويتم اتخاذ الاحتياطات اللازمة وفقًا لنتائج المراقبة.","5":"تم اعتماد الممارسات الناضجة فيما يتعلق بالاعتراف وإصدار الشهادات للدبلومات والدرجات والمؤهلات الأخرى التي تتم بما يتماشى مع الأهداف المؤسسية وبطريقة مستدامة في جميع أنحاء المؤسسة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (26, 'B.3.1', 'Öğretim Yöntem ve Teknikleri', 'Teaching Methods and Techniques', 'طرق وتقنيات التدريس', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Öğrenme-öğretme süreçlerinde öğrenci merkezli yaklaşımlar bulunmamaktadır.","2":"Öğrenme-öğretme süreçlerinde öğrenci merkezli yaklaşımlar uygulanmasına yönelik planlamalar vardır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamayan uygulamalar vardır.","3":"Tüm alanlarda öğrenme-öğretme süreçlerinde aktif ve etkileşimli öğrenci katılımını sağlayan güncel, disiplinlerarası çalışmaya teşvik eden ve araştırma/öğrenme ve öğrenci odaklı öğretim yöntem ve teknikleri uygulanmakta ve bu uygulamalardan bazı sonuçlar elde edilmektedir. Ancak bu uygulamaların sonuçlarının izlenmesi yapılmamaktadır.","4":"Öğrenme-öğretme süreçlerinde aktif ve etkileşimli öğrenci katılımını sağlayan güncel, disiplinlerarası çalışmaya teşvik eden ve araştırma/öğrenme ve öğrenci odaklı öğretim yaklaşımı uygulamalarından elde edilen bulgular, sistematik olarak izlenerek paydaşlarla birlikte değerlendirilmekte ve izlem sonuçlarına göre önlem alınmaktadır.","5":"Kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde yürütülen öğretim yöntem ve tekniklerine ilişkin olgunlaşmış uygulamalar kurumun tamamında benimsenmiştir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no student-centered approaches in learning-teaching processes.","2":"There are plans to implement student-centered approaches in learning-teaching processes. However, there are no applications made in line with these plans, or there are applications that do not cover all areas.","3":"Research/learning and student-focused teaching methods and techniques that ensure active and interactive student participation in learning-teaching processes in all fields, encourage current, interdisciplinary study, and are applied and some results are obtained from these applications. However, the results of these practices are not monitored.","4":"Findings obtained from research/learning and student-centered teaching approach practices that ensure active and interactive student participation in learning-teaching processes, encourage current, interdisciplinary study, are systematically monitored and evaluated together with stakeholders, and precautions are taken according to the monitoring results.","5":"Mature practices regarding teaching methods and techniques carried out in a sustainable manner in line with institutional goals have been adopted throughout the institution; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد أساليب تركز على الطالب في عمليات التعلم والتعليم.","2":"هناك خطط لتنفيذ الأساليب التي تركز على الطالب في عمليات التعلم والتعليم. ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط، أو هناك طلبات لا تغطي جميع المجالات.","3":"يتم تطبيق أساليب وتقنيات البحث/التعلم والتدريس التي تركز على الطالب والتي تضمن مشاركة الطلاب النشطة والتفاعلية في عمليات التعلم والتعليم في جميع المجالات، وتشجع الدراسة الحالية ومتعددة التخصصات، ويتم تطبيقها ويتم الحصول على بعض النتائج من هذه التطبيقات. ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"النتائج التي تم الحصول عليها من ممارسات البحث/التعلم ونهج التدريس المرتكز على الطالب والتي تضمن مشاركة الطلاب النشطة والتفاعلية في عمليات التعلم والتعليم، وتشجع الدراسة الحالية متعددة التخصصات، تتم مراقبتها وتقييمها بشكل منهجي مع أصحاب المصلحة، ويتم اتخاذ الاحتياطات وفقًا لنتائج المراقبة.","5":"تم اعتماد الممارسات الناضجة فيما يتعلق بأساليب وتقنيات التدريس التي يتم تنفيذها بطريقة مستدامة بما يتماشى مع الأهداف المؤسسية في جميع أنحاء المؤسسة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (27, 'B.3.2', 'Ölçme ve Değerlendirme', 'Measurement and Evaluation', 'القياس والتقييم', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Programda öğrenci merkezli ölçme ve değerlendirmeye ilişkin planlamalar veya tanımlı süreçler bulunmamaktadır.","2":"Programda tasarlanmış olan öğrenci merkezli ölçme ve değerlendirmeye ilişkin planlamalar ve tanımlı süreçler vardır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamayan uygulamalar vardır.","3":"Tüm alanlarda öğrenci merkezli ölçme ve değerlendirmeye ilişkin uygulamalar vardır ve bu uygulamalardan bazı sonuçlar elde edilmiştir. Ancak bu ölçme ve değerlendirme sisteminin sonuçlarının izlenmesi yapılmamaktadır.","4":"Tüm alanlarda öğrenci merkezli ölçme ve değerlendirmeye ilişkin olgunlaşmış uygulamalardan elde edilen bulgular, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde yürütülen öğrenci merkezli ölçme ve değerlendirmeye ilişkin olgunlaşmış uygulamalar kurumun tamamında benimsenmiştir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no plans or defined processes for student-centered measurement and evaluation in the program.","2":"There are plans and defined processes for student-centered measurement and evaluation designed in the program. However, there are no applications made in line with these plans, or there are applications that do not cover all areas.","3":"There are practices regarding student-centered measurement and evaluation in all fields, and some results have been obtained from these practices. However, the results of this measurement and evaluation system are not monitored.","4":"The findings obtained from mature practices regarding student-centered measurement and evaluation in all fields are systematically monitored and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"Mature practices regarding student-centered measurement and evaluation carried out in line with institutional goals and in a sustainable manner have been adopted throughout the institution; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد خطط أو عمليات محددة للقياس والتقييم المرتكز على الطالب في البرنامج.","2":"هناك خطط وعمليات محددة للقياس والتقييم المرتكز على الطالب والمصممة في البرنامج. ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط، أو هناك طلبات لا تغطي جميع المجالات.","3":"هناك ممارسات تتعلق بالقياس والتقويم المرتكز على الطالب في جميع المجالات، وقد تم الحصول على بعض النتائج من هذه الممارسات. ومع ذلك، لا يتم رصد نتائج نظام القياس والتقييم هذا.","4":"تتم مراقبة النتائج التي تم الحصول عليها من الممارسات الناضجة فيما يتعلق بالقياس والتقييم المرتكز على الطالب في جميع المجالات بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تم اعتماد الممارسات الناضجة فيما يتعلق بالقياس والتقييم الذي يركز على الطالب والذي يتم تنفيذه بما يتماشى مع الأهداف المؤسسية وبطريقة مستدامة في جميع أنحاء المؤسسة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (28, 'B.3.3', 'Öğrenci Geri Bildirimleri', 'Student Feedback', 'ردود فعل الطلاب', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda öğrenci geri bildirimlerinin alınmasına yönelik mekanizmalar bulunmamaktadır.","2":"Kurumda öğrencilerin geri bildirimlerinin (ders, dersin öğretim elemanı, diploma programı, hizmet ve genel memnuniyet seviyesi, vb.) alınmasına ilişkin mekanizmalar oluşturulmuştur. Ancak hiç uygulama yoktur veya tüm birimleri kapsamayan uygulamalar vardır.","3":"Öğrenci geri bildirimleri (ders, dersin öğretim elemanı, diploma programı, hizmet ve genel memnuniyet seviyesi, vb.) sistematik olarak (her yarıyıl ya da her akademik yılsonunda) alınmaktadır. Ancak alınan geri bildirimler iyileştirmeye yönelik karar alma süreçlerinde kullanılmamaktadır.","4":"Programda tüm öğrenci gruplarının geri bildirimlerinin alınmasına ilişkin uygulamalardan (geçerlilik ve güvenirliği sağlanmış, farklı araçlar içeren) elde edilen bulgular, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde yürütülen öğrenci geri bildirimlerinin alınmasına ilişkin olgunlaşmış uygulamalar kurumun tamamında benimsenmiştir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no mechanisms for receiving student feedback in the institution.","2":"Mechanisms have been established in the institution to receive student feedback (course, course instructor, diploma program, service and general satisfaction level, etc.). However, there are no applications or there are applications that do not cover all units.","3":"Student feedback (course, course instructor, diploma program, service and general satisfaction level, etc.) is received systematically (at the end of each semester or each academic year). However, the feedback received is not used in decision-making processes for improvement.","4":"The findings obtained from the practices related to receiving feedback from all student groups in the program (containing different tools, whose validity and reliability are ensured) are systematically monitored and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"Mature practices for receiving student feedback, carried out in a sustainable manner and in line with institutional objectives, have been adopted throughout the institution; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد آليات لتلقي آراء الطلاب في المؤسسة.","2":"تم إنشاء آليات في المؤسسة لتلقي آراء الطلاب (المقرر الدراسي، مدرس المقرر، برنامج الدبلوم، مستوى الخدمة والرضا العام، إلخ). لكن لا يوجد طلبات أو هناك طلبات لا تغطي جميع الوحدات.","3":"يتم تلقي تعليقات الطلاب (الدورة، مدرس الدورة، برنامج الدبلوم، الخدمة ومستوى الرضا العام، وما إلى ذلك) بشكل منهجي (في نهاية كل فصل دراسي أو كل عام دراسي). ومع ذلك، لا يتم استخدام التعليقات الواردة في عمليات صنع القرار من أجل التحسين.","4":"تتم مراقبة النتائج التي تم الحصول عليها من الممارسات المتعلقة بتلقي التغذية الراجعة من جميع مجموعات الطلاب في البرنامج (التي تحتوي على أدوات مختلفة، والتي يتم التأكد من صحتها وموثوقيتها) بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تم اعتماد ممارسات ناضجة لتلقي تعليقات الطلاب، والتي يتم تنفيذها بطريقة مستدامة وبما يتماشى مع الأهداف المؤسسية، في جميع أنحاء المؤسسة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (29, 'B.3.4', 'Akademik Danışmanlık', 'Academic Advising', 'الإرشاد الأكاديمي', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda tanımlı bir akademik danışmanlık süreci bulunmamaktadır.","2":"Kurumda tanımlı bir akademik danışmanlık süreci bulunmaktadır. Ancak hiç uygulama yoktur veya tüm alanları kapsamayan uygulamalar vardır.","3":"Kurumda akademik danışmanlık uygulamaları vardır ve bu uygulamalardan bazı sonuçlar elde edilmiştir. Ancak bu sonuçların izlenmesi yapılmamaktadır.","4":"Kurumda akademik danışmanlığa ilişkin yürütülen uygulamalardan elde edilen bulgular, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde yürütülen akademik danışmanlığa ilişkin olgunlaşmış uygulamalar kurumun tamamında benimsenmiştir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no defined academic counseling process in the institution.","2":"The institution has a defined academic consultancy process. However, there are no applications or there are applications that do not cover all areas.","3":"The institution has academic consultancy practices and some results have been obtained from these practices. However, these results are not monitored.","4":"The findings obtained from the academic consultancy practices carried out in the institution are systematically monitored and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"Mature practices regarding academic advising, carried out in a sustainable manner in line with institutional goals, have been adopted throughout the institution; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد عملية محددة للإرشاد الأكاديمي في المؤسسة.","2":"لدى المؤسسة عملية استشارية أكاديمية محددة. لكن لا توجد طلبات أو هناك تطبيقات لا تغطي كافة المجالات.","3":"لدى المؤسسة ممارسات استشارية أكاديمية وقد تم الحصول على بعض النتائج من هذه الممارسات. ومع ذلك، لا يتم رصد هذه النتائج.","4":"تتم مراقبة النتائج التي تم الحصول عليها من ممارسات الاستشارة الأكاديمية التي يتم تنفيذها في المؤسسة بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تم اعتماد الممارسات الناضجة فيما يتعلق بالإرشاد الأكاديمي، والتي يتم تنفيذها بطريقة مستدامة بما يتماشى مع الأهداف المؤسسية، في جميع أنحاء المؤسسة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (30, 'B.4.1', 'Atama, Yükseltme ve Görevlendirme Kriterleri', 'Appointment, Promotion and Assignment Criteria', 'معايير التعيين والترقية والتعيين', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun atama, yükseltme ve ders görevlendirme kriterleri ve süreçleri tanımlanmamıştır.","2":"Kurumun atama, yükseltme ve ders görevlendirme kriterleri tanımlanmış; ancak planlamada alana özgü ihtiyaçlar irdelenmemiştir.","3":"Kurumun tüm alanlar için tanımlı ve paydaşlarca bilinen atama, yükseltme ve ders görevlendirme kriterleri uygulanmakta ve karar almalarda (eğitim-öğretim kadrosunun işe alınması, atanması, yükseltilmesi ve ders görevlendirmeleri vb.) kullanılmaktadır. Ancak bu uygulamaların sonuçlarının izlenmesi yapılmamaktadır.","4":"Atama, yükseltme ve ders görevlendirmesine ilişkin uygulanan kriterlerin sonuçları, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Tüm alanlarda atama, yükseltme ve ders görevlendirmesine ilişkin kurumsal amaçlar doğrultusunda, sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiştir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution''s appointment, promotion and course assignment criteria and processes are not defined.","2":"The institution''s appointment, promotion and course assignment criteria are defined; However, site-specific needs were not examined in the planning.","3":"The institution''s appointment, promotion and course assignment criteria, defined for all fields and known to stakeholders, are applied and used in decision-making (recruitment, appointment, promotion and course assignments of teaching staff, etc.). However, the results of these practices are not monitored.","4":"The results of the criteria applied for appointment, promotion and course assignment are systematically monitored and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"In line with institutional objectives regarding appointment, promotion and course assignment in all areas, sustainable and mature practices have been adopted throughout the institution; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لم يتم تحديد معايير وعمليات التعيين والترقية وتعيين المقرر الدراسي في المؤسسة.","2":"يتم تحديد معايير التعيين والترقية وتعيين الدورة في المؤسسة؛ ومع ذلك، لم يتم فحص الاحتياجات الخاصة بالموقع في التخطيط.","3":"يتم تطبيق معايير التعيين والترقية وتعيين المقررات الدراسية في المؤسسة، والمحددة لجميع المجالات والمعروفة لدى أصحاب المصلحة، واستخدامها في اتخاذ القرار (التوظيف والتعيين والترقية وتعيين المقررات الدراسية لأعضاء هيئة التدريس، وما إلى ذلك). ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"تتم مراقبة نتائج المعايير المطبقة للتعيين والترقية وتعيين الدورة بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تماشيًا مع الأهداف المؤسسية فيما يتعلق بالتعيين والترقية وتحديد المقررات الدراسية في جميع المجالات، تم اعتماد ممارسات مستدامة وناضجة في جميع أنحاء المؤسسة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (31, 'B.4.2', 'Öğretim Yetkinliği', 'Teaching Competence', 'الكفاءة التدريسية', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun öğretim elemanlarının öğretim yetkinliğini geliştirmek üzere planlamalar bulunmamaktadır.","2":"Kurumun öğretim elemanlarının yenilikçi yaklaşımlar, materyal geliştirme, yetkinlik kazandırma ve kalite güvence sistemi gibi öğretim yetkinliklerinin geliştirilmesine ilişkin planlar bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır veya kurumun tümünü kapsamayan bazı uygulamalar (eğiticilerin eğitimi etkinlikleri) bulunmaktadır.","3":"Kurumun öğretim elemanlarının öğretim yetkinliğini geliştirmek üzere uygulamalar vardır ve bunlar tüm alanları kapsamaktadır. Ancak bu uygulamaların sonuçlarının izlenmesi yapılmamaktadır.","4":"Kurumun öğretim elemanlarının öğretim yetkinliğini geliştirmek üzere gerçekleştirilen uygulamalardan elde edilen bulgular sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Öğretim elemanlarının kurumsal amaçlar doğrultusunda öğretim yetkinliklerinin gelişimine ilişkin sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiştir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no plans to improve the teaching competence of the institution''s faculty members.","2":"There are plans to develop the teaching competencies of the institution''s faculty members, such as innovative approaches, material development, competency acquisition and quality assurance system. However, there are no practices made in line with these plans, or there are some practices (training of trainers activities) that do not cover the entire institution.","3":"There are practices to improve the teaching competence of the institution''s faculty members and these cover all areas. However, the results of these practices are not monitored.","4":"The findings obtained from the practices carried out to improve the teaching competence of the institution''s faculty members are systematically monitored and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"Sustainable and mature practices regarding the development of teaching competencies of faculty members in line with institutional goals have been adopted throughout the institution; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد خطط لتحسين الكفاءة التدريسية لأعضاء هيئة التدريس بالمؤسسة.","2":"هناك خطط لتطوير الكفاءات التدريسية لأعضاء هيئة التدريس بالمؤسسة، مثل الأساليب المبتكرة، وتطوير المواد، واكتساب الكفاءات، ونظام ضمان الجودة. إلا أنه لا توجد ممارسات تتماشى مع هذه الخطط، أو أن هناك بعض الممارسات (أنشطة تدريب المدربين) لا تغطي المؤسسة بأكملها.","3":"هناك ممارسات لتحسين الكفاءة التدريسية لأعضاء هيئة التدريس بالمؤسسة، وهي تغطي جميع المجالات. ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"تتم مراقبة النتائج التي تم الحصول عليها من الممارسات التي تم تنفيذها لتحسين الكفاءة التعليمية لأعضاء هيئة التدريس بالمؤسسة بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تم اعتماد ممارسات مستدامة وناضجة فيما يتعلق بتطوير الكفاءات التعليمية لأعضاء هيئة التدريس بما يتماشى مع الأهداف المؤسسية في جميع أنحاء المؤسسة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (32, 'B.4.3', 'Eğitim Faaliyetlerine Yönelik Teşvik ve Ödüllendirme', 'Incentive and Reward for Educational Activities', 'حوافز ومكافآت للأنشطة التعليمية', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Öğretim kadrosuna yönelik teşvik ve ödüllendirilme mekanizmaları bulunmamaktadır.","2":"Öğretim kadrosunu teşvik ve ödüllendirme mekanizmalarının oluşturulmasına yönelik planlar bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamayan bazı uygulamalar bulunmaktadır.","3":"Kurumun öğretim kadrosunu teşvik etme ve ödüllendirme uygulamaları öğretim elemanlarının yetkinlikleri dikkate alınarak adil ve şeffaf şekilde sürdürülmektedir ve bunlar tüm alanları kapsamaktadır. Ancak uygulama sonuçları izlenmemektedir.","4":"Kurumun öğretim kadrosunun teşvik etme ve ödüllendirmeye ilişkin uygulamalardan elde edilen bulgular sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Öğretim kadrosunu, kurumsal amaçlar doğrultusunda teşvik etme ve ödüllendirmeye ilişkin, sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiştir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no incentive and reward mechanisms for teaching staff.","2":"There are plans to create incentive and reward mechanisms for teaching staff. However, there are no applications made in line with these plans, or there are some applications that do not cover all areas.","3":"The institution''s practices of encouraging and rewarding its teaching staff are carried out in a fair and transparent manner, taking into account the competencies of the teaching staff, and these cover all areas. However, the application results are not monitored.","4":"The findings obtained from the institution''s practices regarding encouraging and rewarding the teaching staff are systematically monitored and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"Sustainable and mature practices for encouraging and rewarding faculty in line with institutional goals have been adopted throughout the institution; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد آليات حوافز ومكافآت لأعضاء هيئة التدريس.","2":"هناك خطط لإنشاء آليات الحوافز والمكافآت لأعضاء هيئة التدريس. ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط، أو أن هناك بعض الطلبات التي لا تغطي جميع المجالات.","3":"تتم ممارسات المؤسسة في تشجيع ومكافأة أعضاء هيئة التدريس لديها بطريقة عادلة وشفافة، مع مراعاة كفاءات أعضاء هيئة التدريس، وتغطي جميع المجالات. ومع ذلك، لا يتم رصد نتائج التطبيق.","4":"تتم مراقبة النتائج التي تم الحصول عليها من ممارسات المؤسسة فيما يتعلق بتشجيع ومكافأة أعضاء هيئة التدريس بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تم اعتماد ممارسات مستدامة وناضجة لتشجيع ومكافأة أعضاء هيئة التدريس بما يتماشى مع الأهداف المؤسسية في جميع أنحاء المؤسسة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (33, 'B.5.1', 'Öğrenme Kaynakları', 'Learning Resources', 'مصادر التعلم', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun eğitimöğretim faaliyetlerini sürdürebilmek için uygun nitelik ve nicelikte öğrenme kaynağı (sınıf, laboratuvar, kütüphane, stüdyo gibi yapılar, ders kitapları, insan kaynakları, öğrenme desteği vb.) bulunmamaktadır.","2":"Kurumun eğitimöğretim faaliyetlerini sürdürebilmek için uygun nitelik ve nicelikte öğrenme kaynaklarının oluşturulmasına yönelik planları vardır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır veya uygulamalar tüm birimleri kapsamamaktadır.","3":"Kurumun eğitim-öğretim faaliyetlerini sürdürebilmek için uygun nitelik ve nicelikte öğrenme kaynakları alanlar arası denge gözetilerek sağlanmaktadır. Ancak bu kaynakların kullanımına yönelik sonuçlar izlenmemektedir.","4":"Kurumun tüm alanlarındaki uygun nicelik ve nitelikte, erişilebilir öğrenme kaynakları sağlamak üzere öğrenme kaynakları yönetilmektedir. Tüm bu uygulamalardan elde edilen bulgular, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar/talepler doğrultusunda kaynaklar çeşitlendirilmektedir.","5":"Kurumun tüm alanlarındaki uygun nicelik ve nitelikte, erişilebilir öğrenme kaynakları, kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde yönetilmektedir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have learning resources of appropriate quality and quantity (structures such as classrooms, laboratories, libraries, studios, textbooks, human resources, learning support, etc.) to continue its educational activities.","2":"The institution has plans to create learning resources of appropriate quality and quantity in order to continue its educational activities. However, there are no practices made in line with these plans or the practices do not cover all units.","3":"In order to continue the educational activities of the institution, learning resources of appropriate quality and quantity are provided by considering the balance between fields. However, the results of the use of these resources are not monitored.","4":"Learning resources are managed to provide accessible learning resources of appropriate quantity and quality in all areas of the institution. The findings obtained from all these applications are systematically monitored and the monitoring results are evaluated together with the stakeholders, precautions are taken and resources are diversified in line with the needs/demands.","5":"Accessible learning resources in appropriate quantity and quality in all areas of the institution are managed in a sustainable manner in line with institutional objectives; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا تمتلك المؤسسة موارد تعليمية ذات جودة وكمية مناسبة (هياكل مثل الفصول الدراسية والمختبرات والمكتبات والاستوديوهات والكتب المدرسية والموارد البشرية ودعم التعلم وما إلى ذلك) لمواصلة أنشطتها التعليمية.","2":"لدى المؤسسة خطط لإنشاء مصادر تعليمية ذات جودة وكمية مناسبة لمواصلة أنشطتها التعليمية. ومع ذلك، لا توجد ممارسات تتماشى مع هذه الخطط أو أن الممارسات لا تغطي جميع الوحدات.","3":"من أجل مواصلة الأنشطة التعليمية للمؤسسة، يتم توفير مصادر التعلم ذات الجودة والكمية المناسبة مع مراعاة التوازن بين المجالات. ومع ذلك، لا يتم رصد نتائج استخدام هذه الموارد.","4":"تتم إدارة مصادر التعلم لتوفير مصادر تعليمية يمكن الوصول إليها بالكمية والنوعية المناسبة في جميع مجالات المؤسسة. تتم مراقبة النتائج التي تم الحصول عليها من جميع هذه التطبيقات بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة، ويتم اتخاذ الاحتياطات وتنويع الموارد بما يتماشى مع الاحتياجات / المتطلبات.","5":"تتم إدارة موارد التعلم التي يمكن الوصول إليها بالكمية والنوعية المناسبة في جميع مجالات المؤسسة بطريقة مستدامة بما يتماشى مع الأهداف المؤسسية؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (34, 'B.5.2', 'Sosyal, Kültürel, Sportif Faaliyetler', 'Social, Cultural, Sportive Activities', 'الأنشطة الاجتماعية والثقافية والرياضية', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda uygun nitelik ve nicelikte sosyal, kültürel ve sportif faaliyetler bulunmamaktadır.","2":"Kurumda uygun nicelik ve nitelikte sosyal, kültürel ve sportif faaliyetler yürütülmesine ilişkin (mekân, mali ve rehberlik desteği sağlamak gibi) planlamalar bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır.","3":"Kurumda uygun nicelik ve nitelikte sosyal, kültürel ve sportif faaliyetler yürütülmektedir. Ancak bu uygulamaların ve faaliyetlerin sonuçları izlenmemektedir.","4":"Fakültede uygun nicelik ve nitelikte sosyal, kültürel ve sportif faaliyetler kurumsal olarak (program amaçları doğrultusunda) yönetilmektedir (yürütmek üzere destekler sağlanmakta, idari örgütlenme bulunmakta vb.). Tüm bu uygulamalardan elde edilen bulgular, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar/talepler doğrultusunda kaynaklar çeşitlendirilmektedir.","5":"Kurumda uygun nicelik ve nitelikte sosyal, kültürel ve sportif faaliyetler, kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde yönetilmektedir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no social, cultural and sports activities of appropriate quality and quantity in the institution.","2":"The institution has plans for carrying out social, cultural and sports activities in appropriate quantity and quality (such as providing venue, financial and guidance support). However, there are no practices made in line with these plans.","3":"Social, cultural and sports activities are carried out in the institution in appropriate quantity and quality. However, the results of these practices and activities are not monitored.","4":"At the faculty, social, cultural and sports activities of appropriate quantity and quality are managed institutionally (in line with program objectives) (support is provided to carry them out, there is an administrative organization, etc.). The findings obtained from all these applications are systematically monitored and the monitoring results are evaluated together with the stakeholders, precautions are taken and resources are diversified in line with the needs/demands.","5":"In the institution, social, cultural and sports activities of appropriate quantity and quality are managed in a sustainable manner in line with corporate objectives; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد أنشطة اجتماعية وثقافية ورياضية ذات نوعية وكمية مناسبة في المؤسسة.","2":"لدى المؤسسة خطط لتنفيذ الأنشطة الاجتماعية والثقافية والرياضية بالكمية والنوعية المناسبة (مثل توفير المكان والدعم المالي والإرشادي). ومع ذلك، لا توجد ممارسات تتماشى مع هذه الخطط.","3":"يتم تنفيذ الأنشطة الاجتماعية والثقافية والرياضية في المؤسسة بالكمية والنوعية المناسبة. ومع ذلك، لا يتم رصد نتائج هذه الممارسات والأنشطة.","4":"في الكلية، تتم إدارة الأنشطة الاجتماعية والثقافية والرياضية ذات الكمية والنوعية المناسبة مؤسسيًا (بما يتماشى مع أهداف البرنامج) (يتم تقديم الدعم لتنفيذها، ويوجد تنظيم إداري، وما إلى ذلك). تتم مراقبة النتائج التي تم الحصول عليها من جميع هذه التطبيقات بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة، ويتم اتخاذ الاحتياطات وتنويع الموارد بما يتماشى مع الاحتياجات / المتطلبات.","5":"تتم في المؤسسة إدارة الأنشطة الاجتماعية والثقافية والرياضية ذات الكمية والنوعية المناسبة بطريقة مستدامة بما يتماشى مع أهداف الشركة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (35, 'B.5.3', 'Tesis ve Altyapılar', 'Facilities and Infrastructures', 'المرافق والبنية التحتية', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda uygun nitelik ve nicelikte tesisler ve altyapı (yemekhane, yurt, teknoloji donanımlı çalışma alanları; sağlık, ulaşım, bilişim hizmetleri) bulunmamaktadır.","2":"Kurumda uygun nitelik ve nicelikte tesis ve altyapının kurulmasına ilişkin planlamalar bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır Kurumda uygun nitelik ve nicelikte tesis ve altyapı kurulmuştur. Ancak bu tesis ve altyapının kullanımına yönelik sonuçlar izlenmemektedir.","3":"Kurumda uygun nitelik ve nicelikteki tesis ve altyapı sağlamak üzere fiziksel kaynaklar ve mekânlar bütünsel olarak yönetilmektedir.","4":"Tüm tesis ve altyapıların kullanımına ilişkin sonuçlar sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar/talepler doğrultusunda kaynaklar çeşitlendirilmektedir.","5":"Kurumda uygun nicelik ve nitelikte, erişilebilir tesis ve altyapı imkânları, kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde yönetilmektedir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have facilities and infrastructure of appropriate quality and quantity (dining hall, dormitory, technology-equipped work areas; health, transportation, IT services).","2":"There are plans for the establishment of facilities and infrastructure of appropriate quality and quantity in the institution. However, there are no applications made in line with these plans. Facilities and infrastructure of appropriate quality and quantity have been established in the institution. However, the results of the use of these facilities and infrastructure are not monitored.","3":"Physical resources and spaces are managed holistically to provide facilities and infrastructure of appropriate quality and quantity in the institution.","4":"The results regarding the use of all facilities and infrastructures are systematically monitored and the monitoring results are evaluated together with the stakeholders, measures are taken and resources are diversified in line with needs/demands.","5":"In the institution, accessible facilities and infrastructure facilities of appropriate quantity and quality are managed in line with corporate objectives and in a sustainable manner; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا تمتلك المؤسسة مرافق وبنية تحتية ذات جودة وكمية مناسبة (قاعة طعام، سكن جامعي، مناطق عمل مجهزة بالتكنولوجيا، الصحة، النقل، خدمات تكنولوجيا المعلومات).","2":"هناك خطط لإنشاء المرافق والبنية التحتية ذات الجودة والكمية المناسبة في المؤسسة. ومع ذلك، لم يتم تقديم أي طلبات تتماشى مع هذه الخطط. تم إنشاء المرافق والبنية التحتية ذات الجودة والكمية المناسبة في المؤسسة. ومع ذلك، لا يتم رصد نتائج استخدام هذه المرافق والبنية التحتية.","3":"تتم إدارة الموارد المادية والمساحات بشكل شامل لتوفير المرافق والبنية التحتية ذات الجودة والكمية المناسبة في المؤسسة.","4":"تتم مراقبة النتائج المتعلقة باستخدام جميع المرافق والبنية التحتية بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة، ويتم اتخاذ التدابير وتنويع الموارد بما يتماشى مع الاحتياجات/الطلبات.","5":"في المؤسسة، تتم إدارة المرافق التي يمكن الوصول إليها ومرافق البنية التحتية ذات الكمية والنوعية المناسبة بما يتماشى مع أهداف الشركة وبطريقة مستدامة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (36, 'B.5.4', 'Engelsiz Fakülte', 'Barrier-Free Faculty', 'كلية خالية من العوائق', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda engelsiz fakülte uygulamalarına ilişkin planlamalar bulunmamaktadır.","2":"Engelsiz fakülte uygulamalarına ilişkin planlama vardır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır.","3":"Kurumda engelsiz fakülte uygulamaları tüm mekânları kapsamaktadır.","4":"Ancak bu uygulamanın sonuçları izlenmemektedir (izlenmemektedir)","5":"Kurumdaki tüm mekânlarda sağlanan engelsiz fakülte uygulamasından elde edilen bulgular sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır."}'::jsonb, NULL, '{"1":"There are no plans for barrier-free faculty practices in the institution.","2":"There is planning for barrier-free faculty practices. However, there are no practices made in line with these plans.","3":"Barrier-free faculty practices cover all spaces in the institution.","4":"However, the results of this application are not monitored (monitored)","5":"The findings obtained from the barrier-free faculty practice provided in all locations in the institution are systematically monitored and the monitoring results are evaluated together with the stakeholders and precautions are taken."}'::jsonb, '{"1":"لا توجد خطط لممارسات أعضاء هيئة التدريس خالية من العوائق في المؤسسة.","2":"هناك تخطيط لممارسات أعضاء هيئة التدريس خالية من العوائق. ومع ذلك، لا توجد ممارسات تتماشى مع هذه الخطط.","3":"تغطي ممارسات أعضاء هيئة التدريس الخالية من العوائق جميع المساحات في المؤسسة.","4":"إلا أن نتائج هذا التطبيق لا يتم رصدها (مراقبتها)","5":"تتم مراقبة النتائج التي تم الحصول عليها من ممارسة أعضاء هيئة التدريس الخالية من العوائق المتوفرة في جميع مواقع المؤسسة بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (37, 'B.5.5', 'Rehberlik, Psikolojik Danışmanlık ve Kariyer Hizmetleri', 'Guidance, Psychological Counseling and Career Services', 'التوجيه والإرشاد النفسي والخدمات المهنية', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda uygun nitelik ve nicelikte rehberlik, psikolojik danışmanlık ve kariyer hizmetlerinin sağlanmasına ilişkin planlama bulunmamaktadır.","2":"Kurumda uygun nitelik ve nicelikte rehberlik, psikolojik danışmanlık ve kariyer hizmetlerinin sağlanmasına ilişkin planlama vardır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır.","3":"Kurumda uygun nitelik ve nicelikte rehberlik, psikolojik danışmanlık ve kariyer hizmetleri sağlanmaktadır. Ancak bu uygulamanın sonuçları izlenmemektedir.","4":"Kurumda sağlanan uygun nitelik ve nicelikteki rehberlik, psikolojik danışmanlık ve kariyer hizmetleri bütünsel olarak yönetilmektedir (veya bu hizmetleri Rektörlük bünyesinde yöneten bir merkezin olması vb. ). Bu hizmetlere ilişkin sonuçlar sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar/talepler doğrultusunda kaynaklar çeşitlendirilmektedir.","5":"Kurumda sağlanan uygun nitelik ve nicelikteki rehberlik, psikolojik danışmanlık ve kariyer hizmetleri, kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde yönetilmektedir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no plan in the institution to provide guidance, psychological counseling and career services of appropriate quality and quantity.","2":"The institution has a plan to provide guidance, psychological counseling and career services of appropriate quality and quantity. However, there are no practices made in line with these plans.","3":"Guidance, psychological counseling and career services are provided in the institution in appropriate quality and quantity. However, the results of this practice are not monitored.","4":"Guidance, psychological counseling and career services of appropriate quality and quantity provided in the institution are managed holistically (or there is a center that manages these services within the Rectorate, etc.). The results of these services are systematically monitored and the monitoring results are evaluated together with the stakeholders, measures are taken and resources are diversified in line with needs/demands.","5":"Guidance, psychological counseling and career services of appropriate quality and quantity provided in the institution are managed in line with corporate objectives and in a sustainable manner; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد خطة في المؤسسة لتقديم التوجيه والإرشاد النفسي والخدمات المهنية بالجودة والكمية المناسبة.","2":"لدى المؤسسة خطة لتقديم التوجيه والإرشاد النفسي والخدمات المهنية بالجودة والكمية المناسبة. ومع ذلك، لا توجد ممارسات تتماشى مع هذه الخطط.","3":"يتم توفير التوجيه والاستشارة النفسية والخدمات المهنية في المؤسسة بالجودة والكمية المناسبة. ومع ذلك، لا يتم رصد نتائج هذه الممارسة.","4":"تتم إدارة التوجيه والاستشارة النفسية والخدمات المهنية ذات الجودة والكمية المناسبة المقدمة في المؤسسة بشكل كلي (أو يوجد مركز يدير هذه الخدمات داخل الجامعة، وما إلى ذلك). تتم مراقبة نتائج هذه الخدمات بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة، ويتم اتخاذ التدابير وتنويع الموارد بما يتماشى مع الاحتياجات/الطلبات.","5":"تتم إدارة التوجيه والاستشارة النفسية والخدمات المهنية ذات الجودة والكمية المناسبة المقدمة في المؤسسة بما يتماشى مع أهداف الشركة وبطريقة مستدامة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (38, 'B.6.1', 'Program Çıktılarının İzlenmesi ve Güncellenmesi', 'Monitoring and Updating Program Outputs', 'مراقبة وتحديث مخرجات البرنامج', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Program çıktılarının izlenmesine ve güncellenmesine ilişkin herhangi bir mekanizma bulunmamaktadır.","2":"Program çıktılarının izlenmesine ve güncellenmesine ilişkin mekanizmalar (tanımlı süreçler ve performans göstergeleri) oluşturulmuştur. Ancak hiçbir uygulama bulunmamaktadır.","3":"Kurumda program çıktılarının izlenmesine ilişkin uygulamalar gerçekleştirilmiş ve bazı sonuçlar elde edilmiştir. Ancak bu sonuçların değerlendirilmesi, karar almalarda ve güncellemelerde kullanılması gerçekleştirilmemiştir.","4":"Kurumda program çıktıları sistematik olarak (yıllık ve program süresinin sonunda periyodik olarak) ve kurumsal amaçlar doğrultusunda (eğitim-öğretim politikası ve amaçları) izlenmektedir. Bu izleme sonuçları paydaşlarla birlikte değerlendirilerek güncellemeler yapılmaktadır.","5":"Kurumda program çıktılarının, kurumsal amaçlar doğrultusunda ve sürdürülebilir şekilde izlenmesi güvence altına alınmıştır; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no mechanism for monitoring and updating program outputs.","2":"Mechanisms (defined processes and performance indicators) for monitoring and updating program outcomes have been established. However, there is no application.","3":"Practices regarding monitoring program outcomes have been carried out in the institution and some results have been obtained. However, these results have not been evaluated and used in decision-making and updates.","4":"In the institution, program outcomes are monitored systematically (annually and periodically at the end of the program period) and in line with institutional goals (education-training policy and objectives). These monitoring results are evaluated together with stakeholders and updates are made.","5":"It is ensured that program outcomes are monitored in a sustainable manner in line with institutional objectives; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد آلية لرصد وتحديث مخرجات البرنامج.","2":"تم إنشاء آليات (عمليات محددة ومؤشرات أداء) لرصد وتحديث نتائج البرنامج. ومع ذلك، لا يوجد أي تطبيق.","3":"تم تنفيذ الممارسات المتعلقة بمراقبة نتائج البرنامج في المؤسسة وتم الحصول على بعض النتائج. ومع ذلك، لم يتم تقييم هذه النتائج واستخدامها في اتخاذ القرارات والتحديثات.","4":"في المؤسسة، تتم مراقبة نتائج البرنامج بشكل منهجي (سنويًا ودوريًا في نهاية فترة البرنامج) وبما يتماشى مع الأهداف المؤسسية (سياسة وأهداف التعليم والتدريب). يتم تقييم نتائج المراقبة هذه مع أصحاب المصلحة ويتم إجراء التحديثات.","5":"التأكد من مراقبة نتائج البرنامج بطريقة مستدامة بما يتماشى مع الأهداف المؤسسية. وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (39, 'B.6.2', 'Mezun İzleme Sistemi', 'Alumni Tracking System', 'نظام متابعة الخريجين', 2, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda herhangi bir mezun izleme sistemi bulunmamaktadır.","2":"Mezun izleme sistemine ilişkin planlar bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır.","3":"Mezun izleme sistemine ilişkin uygulamalar vardır ve bunlardan bazı sonuçlar elde edilmiştir. Ancak bu sonuçların değerlendirilmesi ve karar almalarda kullanılması gerçekleştirilmemiştir.","4":"Kurumda sistematik olarak ve program amaçları doğrultusunda (eğitim-öğretim politikası ve amaçları) mezunlar izlenmekte ve izlem sonuçlarına göre önlemler alınmaktadır.","5":"Kurum mezunlarının program amaçları doğrultusunda izlenmesini güvence altına almış, mezunlar kurumun kalite güvence sisteminin bir parçası haline gelmiştir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no graduate tracking system in the institution.","2":"There are plans for a graduate tracking system. However, there are no practices made in line with these plans.","3":"There are applications regarding the graduate tracking system and some results have been obtained from them. However, these results have not been evaluated and used in decision-making.","4":"Graduates are monitored systematically and in line with the program objectives (education-training policy and objectives) in the institution, and measures are taken according to the monitoring results.","5":"The institution has ensured that its graduates are monitored in line with program objectives, and graduates have become part of the institution''s quality assurance system; The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا يوجد نظام لتتبع الخريجين في المؤسسة.","2":"هناك خطط لنظام تتبع الخريجين. ومع ذلك، لا توجد ممارسات تتماشى مع هذه الخطط.","3":"هناك تطبيقات بخصوص نظام متابعة الخريجين وتم الحصول على بعض النتائج منها. ومع ذلك، لم يتم تقييم هذه النتائج واستخدامها في صنع القرار.","4":"تتم مراقبة الخريجين بشكل منهجي وبما يتماشى مع أهداف البرنامج (سياسة وأهداف التعليم والتدريب) في المؤسسة، ويتم اتخاذ التدابير وفقا لنتائج المراقبة.","5":"حرصت المؤسسة على مراقبة خريجيها بما يتماشى مع أهداف البرنامج، وأصبح الخريجون جزءًا من نظام ضمان الجودة في المؤسسة؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (40, 'C.1.1', 'Kurumun Araştırma Politikası, Hedefleri ve Stratejisi', 'Research Policy, Goals and Strategy of the Institution', 'سياسة البحث وأهدافه وإستراتيجيته', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun tanımlı araştırma politikası, stratejisi ve hedefleri bulunmamaktadır.","2":"Kurumun paydaşlarıyla oluşturduğu araştırmaya bakış açısını, araştırma faaliyetlerinde izleyeceği ilkeleri, araştırmadaki önceliklerini ve araş tırma kaynaklarını yönetmedeki tercihlerini ifade eden araştırma politikası, stratejisi ve hedefleri bulunmaktadır. Ancak bunları hayata geçirmek üzere mekanizmalar veya uygulamalar bulunmamaktadır.","3":"Kurumun tanımlı araştırma politikası, stratejisi ve hed efleri doğrultusunda yapılan uygulamalar bulunmaktadır. Ancak bu uygulamaların sonuçları değerlendirilmemektedir.","4":"Kurumda tüm alanlar tarafından benimsenmiş araştırma politikası, stratejisi ve hedefleri ile ilgili uygulamalar, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek tüm alanları kapsayan önlemler alınmaktadır.","5":"Kurumda araştırma alanındaki faaliyetlerin, araştırma politikası doğrultusunda değer üretebilmesi ve toplumsal faydaya dönüşebilmesi güvence altına alınm ış ve olgunlaşmış uygulamalarla paydaşlarca benimsenmesi sağlanmıştır; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have a defined research policy, strategy and objectives.","2":"The institution has a research policy, strategy and objectives that express its perspective on research with its stakeholders, the principles it will follow in its research activities, its priorities in research and its preferences in managing research resources. However, there are no mechanisms or practices to implement these.","3":"There are practices carried out in line with the defined research policy, strategy and objectives of the institution. However, the results of these applications are not evaluated.","4":"Practices related to the research policy, strategy and objectives adopted by all areas in the institution are systematically monitored and the monitoring results are evaluated together with stakeholders and measures are taken covering all areas.","5":"It is ensured that the activities in the field of research in the institution can produce value and turn into social benefit in line with the research policy, and that they are adopted by stakeholders with mature practices; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"ليس لدى المؤسسة سياسة بحثية واستراتيجية وأهداف محددة.","2":"لدى المؤسسة سياسة واستراتيجية وأهداف بحثية تعبر عن وجهة نظرها بشأن البحث مع أصحاب المصلحة، والمبادئ التي ستتبعها في أنشطتها البحثية، وأولوياتها في البحث وتفضيلاتها في إدارة موارد البحث. لكن لا توجد آليات أو ممارسات لتنفيذها.","3":"هناك ممارسات يتم تنفيذها بما يتماشى مع سياسة واستراتيجية وأهداف البحث المحددة للمؤسسة. ومع ذلك، لا يتم تقييم نتائج هذه التطبيقات.","4":"تتم مراقبة الممارسات المتعلقة بسياسة البحث واستراتيجيته وأهدافه المعتمدة في جميع المجالات في المؤسسة بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ التدابير التي تغطي جميع المجالات.","5":"التأكد من أن الأنشطة في مجال البحث في المؤسسة يمكن أن تنتج قيمة وتتحول إلى منفعة اجتماعية بما يتماشى مع سياسة البحث، وأن يتم اعتمادها من قبل أصحاب المصلحة ذوي الممارسات الناضجة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (41, 'C.1.2', 'Araştırma-Geliştirme Süreçlerinin Yönetimi ve Organizasyonel Yapısı', 'Management and Organizational Structure of Research and Development Processes', 'الإدارة والهيكل التنظيمي لعمليات البحث والتطوير', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun araştırmageliştirme süreçlerinin yönetimi ve organizasyonel yapısına ilişkin bir planlama bulunmamaktadır.","2":"Kurumun araştırmageliştirme süreçlerinin yönetim ve organizasyonel yapısına ilişkin planlamalar (karışmayan ile müdahaleci spektrumun neresinde konumlandığı, motivasyon ve yönlendirme işlevinin nasıl tasarlandığı, kısa ve uzun vadeli hedeflerin net ve kesin nasıl tanımlandığı, araştırma yönetimi ekibi ve görev tanımları) bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamayan uygulamalar bulunmaktadır.","3":"Kurumunda tüm alanları kapsayıcı şekilde araştırmageliştirme süreçlerinin yönetimi ve organizasyonel yapısı kurumsal tercihler yönünde uygulamaya konularak bazı sonuçlar elde edilmiştir. Ancak bu sonuçlar izlenmemektedir.","4":"Kurumda araştırmageliştirme süreçlerinin yönetimi ile ilişkili sonuçlar ve paydaş görüşleri sistematik olarak izlenmekte ve paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda tüm alanları kapsayan araştırma-geliştirme yönetimi, kurumsal amaçlar (araştırma politikası, hedefleri, stratejisi) doğrultusunda bütünleştirici, sürdürülebilir ve olgunlaşmış uygulamalarla kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no plan regarding the management and organizational structure of the institution''s research and development processes.","2":"There are plans regarding the management and organizational structure of the institution''s research and development processes (where it is located on the non-interventionist and interventionist spectrum, how the motivation and guidance function is designed, how short and long-term goals are clearly and precisely defined, the research management team and job descriptions). However, there are no applications made in line with these plans, or there are applications that do not cover all areas.","3":"Some results have been achieved by implementing the management and organizational structure of research and development processes in the institution, covering all areas, in line with institutional preferences. However, these results are not monitored.","4":"The results and stakeholder opinions related to the management of research and development processes in the institution are systematically monitored and measures are taken by evaluating them together with the stakeholders.","5":"Research and development management, covering all areas in the institution, has been adopted and secured throughout the institution with integrative, sustainable and mature practices in line with institutional goals (research policy, objectives, strategy); The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد خطة فيما يتعلق بالهيكل الإداري والتنظيمي لعمليات البحث والتطوير في المؤسسة.","2":"هناك خطط تتعلق بالإدارة والهيكل التنظيمي لعمليات البحث والتطوير في المؤسسة (حيث تقع على الطيف غير التدخلي والتدخلي، وكيفية تصميم وظيفة التحفيز والتوجيه، ومدى تحديد الأهداف القصيرة والطويلة المدى بشكل واضح ودقيق، وفريق إدارة البحث والتوصيف الوظيفي). ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط، أو هناك طلبات لا تغطي جميع المجالات.","3":"وقد تم تحقيق بعض النتائج من خلال تنفيذ الهيكل الإداري والتنظيمي لعمليات البحث والتطوير في المؤسسة، بحيث يغطي جميع المجالات، بما يتماشى مع التفضيلات المؤسسية. ومع ذلك، لا يتم رصد هذه النتائج.","4":"تتم مراقبة النتائج وآراء أصحاب المصلحة المتعلقة بإدارة عمليات البحث والتطوير في المؤسسة بشكل منهجي ويتم اتخاذ التدابير من خلال تقييمها مع أصحاب المصلحة.","5":"تم اعتماد وتأمين إدارة البحث والتطوير، التي تغطي جميع المجالات في المؤسسة، في جميع أنحاء المؤسسة بممارسات متكاملة ومستدامة وناضجة بما يتماشى مع الأهداف المؤسسية (سياسة البحث والأهداف والاستراتيجية)؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (42, 'C.1.3', 'Araştırmaların Yerel/Bölgesel/Ulusal İhtiyaç ve Taleplerle İlişkisi', 'Relationship of Research to Local/Regional/National Needs and Demands', 'علاقة البحث بالاحتياجات والطلبات المحلية/الإقليمية/الوطنية', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurum araştırmaların planlaması, yürütülmesi veya yönetilmesinde yerel, bölgesel ve ulusal ihtiyaç, talep ve değişimleri dikkate almamaktadır.","2":"Kurum, araştırmaların planlamasında, yürütülmesinde veya yönetilmesinde yerel, bölgesel ve ulusal ihtiyaç, talep ve değişimleri dikkate almaktadır. Ancak bu uygulamalar tüm alanları kapsamamaktadır veya kurumun araştırma politikası, hedefleri ve stratejisine yansıtılmamaktadır.","3":"Kurum araştırma ile ilişkili tüm alanlardaki araştırmaların planlamasında, yürütülmesinde veya yönetilmesinde yerel, bölgesel ve ulusal ihtiyaç, talep ve değişimleri dikkate almaktadır. Ancak bu uygulamalarla ilgili sonuçlar izlenmemektedir.","4":"Kurumda araştırma sonuçlar; yerel, bölgesel ve ulusal ihtiyaç ve taleplerle ilişkili olarak sistematik ve kurumun iç kalite güvencesi sistemiyle uyumlu olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlem alınmaktadır.","5":"Kurumda araştırmaların; yerel, bölgesel ve ulusal ihtiyaç ve taleplere dini sosyokültürel katkısı ile (ulusal/uluslararası) değerlendirilmesi kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun bu hususta kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not take into account local, regional and national needs, demands and changes in the planning, conduct or management of research.","2":"The institution takes into account local, regional and national needs, demands and changes in the planning, conduct or management of research. However, these practices do not cover all areas or are not reflected in the institution''s research policy, objectives and strategy.","3":"The institution takes into account local, regional and national needs, demands and changes in the planning, conduct or management of research in all research-related fields. However, the results of these practices are not monitored.","4":"Research results in the institution; It is monitored systematically and in accordance with the institution''s internal quality assurance system in relation to local, regional and national needs and demands, and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"Research in the institution; The evaluation of local, regional and national needs and demands with their religious socio-cultural contribution (national/international) is adopted and guaranteed throughout the institution; The institution has many unique and innovative practices in this regard, and some of these practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا تأخذ المؤسسة في الاعتبار الاحتياجات والمتطلبات والتغيرات المحلية والإقليمية والوطنية في تخطيط أو إجراء أو إدارة البحوث.","2":"تأخذ المؤسسة في الاعتبار الاحتياجات والمتطلبات والتغيرات المحلية والإقليمية والوطنية في تخطيط أو إجراء أو إدارة البحوث. ومع ذلك، فإن هذه الممارسات لا تغطي جميع المجالات أو لا تنعكس في سياسة البحث وأهدافه واستراتيجيته.","3":"تأخذ المؤسسة في الاعتبار الاحتياجات والمتطلبات والتغيرات المحلية والإقليمية والوطنية في تخطيط أو إجراء أو إدارة البحوث في جميع المجالات المتعلقة بالبحث. ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"نتائج البحوث في المؤسسة؛ وتتم مراقبتها بشكل منهجي ووفقًا لنظام ضمان الجودة الداخلي للمؤسسة فيما يتعلق بالاحتياجات والمتطلبات المحلية والإقليمية والوطنية، ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"البحث في المؤسسة؛ يتم اعتماد وضمان تقييم الاحتياجات والمتطلبات المحلية والإقليمية والوطنية مع مساهمتها الاجتماعية والثقافية الدينية (الوطنية / الدولية) في جميع أنحاء المؤسسة؛ ولدى المؤسسة العديد من الممارسات الفريدة والمبتكرة في هذا الصدد، وبعض هذه الممارسات تتخذها مؤسسات أخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (43, 'C.2.1', 'Araştırma Kaynakları: Fiziki, Teknik, Mali', 'Research Resources: Physical, Technical, Financial', 'مصادر البحث: المادية والفنية والمالية', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun araştırma ve geliştirme faaliyetlerini sürdürebilmesi için uygun nitelik ve nicelikte fiziki, teknik ve mali kaynakları bulunmamaktadır.","2":"Kurumun araştırma ve geliştirme faaliyetlerini sürdürebilmek için uygun nitelik ve nicelikte fiziki, teknik ve mali kaynakların oluşturulmasına yönelik planları vardır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır veya uygulamalar tüm alanları kapsamamaktadır.","3":"Kurumun araştırma ve geliştirme faaliyetlerini sürdürebilmek için uygun nitelik ve nicelikte fiziki, teknik ve mali kaynaklar alanlar arası denge gözetilerek sağlanmaktadır. Ancak bu kaynakların kullanımına yönelik sonuçlar izlenmemektedir.","4":"Kurumda araştırma kaynakları, öncelikli araştırma alanlarını destekleyecek ve tüm alanları kapsayacak şekilde yönetilmektedir. Tüm bu uygulamalardan elde edilen bulgular, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar/talepler doğrultusunda kaynaklar çeşitlendirilmektedir.","5":"Kurumun tüm birimlerindeki uygun nicelik ve nitelikte fiziki, teknik ve mali kaynaklar, kurumsal amaçlar (araştırma politikası, hedefleri, stratejisi) doğrultusunda ve sürdürülebilir şekilde yönetilmektedir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have physical, technical and financial resources of appropriate quality and quantity to continue its research and development activities.","2":"The institution has plans to create physical, technical and financial resources of appropriate quality and quantity in order to continue its research and development activities. However, there are no applications made in line with these plans or the applications do not cover all areas.","3":"In order to continue the research and development activities of the institution, physical, technical and financial resources of appropriate quality and quantity are provided by considering the balance between fields. However, the results of the use of these resources are not monitored.","4":"Research resources at the institution are managed to support priority research areas and cover all areas. The findings obtained from all these applications are systematically monitored and the monitoring results are evaluated together with the stakeholders, precautions are taken and resources are diversified in line with the needs/demands.","5":"Physical, technical and financial resources of appropriate quantity and quality in all units of the institution are managed in a sustainable manner in line with institutional objectives (research policy, objectives, strategy); The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا تمتلك المؤسسة الموارد المادية والتقنية والمالية ذات الجودة والكمية المناسبة لمواصلة أنشطتها البحثية والتطويرية.","2":"لدى المؤسسة خطط لإنشاء موارد مادية وتقنية ومالية ذات جودة وكمية مناسبة من أجل مواصلة أنشطتها البحثية والتطويرية. ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط أو أن الطلبات لا تغطي جميع المجالات.","3":"من أجل مواصلة أنشطة البحث والتطوير للمؤسسة، يتم توفير الموارد المادية والتقنية والمالية ذات الجودة والكمية المناسبة مع مراعاة التوازن بين المجالات. ومع ذلك، لا يتم رصد نتائج استخدام هذه الموارد.","4":"تتم إدارة الموارد البحثية في المؤسسة لدعم المجالات البحثية ذات الأولوية وتغطية جميع المجالات. تتم مراقبة النتائج التي تم الحصول عليها من جميع هذه التطبيقات بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة، ويتم اتخاذ الاحتياطات وتنويع الموارد بما يتماشى مع الاحتياجات / المتطلبات.","5":"تتم إدارة الموارد المادية والتقنية والمالية ذات الكمية والنوعية المناسبة في جميع وحدات المؤسسة بطريقة مستدامة بما يتماشى مع الأهداف المؤسسية (سياسة البحث والأهداف والاستراتيجية)؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (44, 'C.2.2', 'Üniversite İçi Kaynaklar', 'Internal University Resources', 'موارد الجامعة الداخلية', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun araştırma ve geliştirme faaliyetleri için üniversite içi kaynakları bulunmamaktadır.","2":"Kurumun araştırma ve geliştirme faaliyetlerini sürdürebilmek için üniversite içi kaynakları vardır. Ancak bu kaynaklardan kurum araştırmacıları yararlanmamaktadır.","3":"Kurumun araştırma ve geliştirme faaliyetlerini sürdürebilmek için uygun nitelik ve nicelikte üniversite içi kaynakları vardır. Üniversite içi kaynaklardan kurum araştırmacıları yararlanmaktadır. Ancak bu kaynakların kullanımına yönelik sonuçlar izlenmemektedir.","4":"Kurumda üniversite içi kaynakların kullanımına yönelik elde edilen bulgular, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar doğrultusunda üniversiteden kaynak çeşitliliği talep edilmektedir.","5":"Kurum araştırmacıları üniversite içi kaynaklarından, kurumsal amaçlar (araştırma politikası, hedefleri, stratejisi) doğrultusunda ve sürdürülebilir şekilde yararlanmaktadır; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have in-university resources for research and development activities.","2":"The institution has in-university resources to continue its research and development activities. However, institutional researchers do not benefit from these resources.","3":"The institution has in-university resources of appropriate quality and quantity to continue its research and development activities. Institutional researchers benefit from internal university resources. However, the results of the use of these resources are not monitored.","4":"The findings obtained regarding the use of university resources in the institution are systematically monitored and the monitoring results are evaluated together with the stakeholders and precautions are taken and a variety of resources is requested from the university in line with the needs.","5":"Institutional researchers benefit from university resources in a sustainable manner in line with institutional goals (research policy, objectives, strategy); The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"ليس لدى المؤسسة موارد داخل الجامعة لأنشطة البحث والتطوير.","2":"تمتلك المؤسسة موارد جامعية لمواصلة أنشطتها البحثية والتطويرية. ومع ذلك، لا يستفيد الباحثون المؤسسيون من هذه الموارد.","3":"تمتلك المؤسسة موارد جامعية ذات نوعية وكمية مناسبة لمواصلة أنشطتها البحثية والتطويرية. يستفيد الباحثون المؤسسيون من موارد الجامعة الداخلية. ومع ذلك، لا يتم رصد نتائج استخدام هذه الموارد.","4":"تتم مراقبة النتائج التي تم الحصول عليها فيما يتعلق باستخدام موارد الجامعة في المؤسسة بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة وطلب مجموعة متنوعة من الموارد من الجامعة بما يتماشى مع الاحتياجات.","5":"يستفيد الباحثون المؤسسيون من موارد الجامعة بطريقة مستدامة بما يتماشى مع الأهداف المؤسسية (سياسة البحث، الأهداف، الإستراتيجية)؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (45, 'C.2.3', 'Üniversite Dışı Kaynaklara Yönelik Yöntem ve Destekler', 'Methods and Support for Non-University Resources', 'طرق ودعم الموارد غير الجامعية', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun araştırma ve geliştirme faaliyetleri için üniversite dışı kaynaklara herhangi bir yönelimi bulunmamaktadır.","2":"Kurumun üniversite dışı kaynakları oluşturmak için planları ve bu kaynakların kullanımına ilişkin yöntem ve destek süreçleri bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamamaktadır.","3":"Kurumun araştırma ve geliştirme faaliyetlerini kurumsal amaçlar doğrultusunda sürdürebilmek için üniversite dışı kaynakların kullanımına yönelik yöntem ve destek planları oluşturulmuş ve tüm alanları kapsayan uygulamalar bulunmaktadır. Ancak bu kaynakların kullanımına ve uygulamalara yönelik sonuçlar izlenmemektedir.","4":"Kurumda, araştırma ve geliştirme faaliyetlerini kurumsal amaçlar doğrultusunda sürdürebilmek için üniversite dışı kaynakların kullanımını destekleyen uygulamalardan elde edilen bulgular, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda, araştırma ve geliştirme faaliyetlerini kurumsal amaçlar (araştırma politikası, hedefleri, stratejisi) doğrultusunda sürdürebilmek için üniversite dışı kaynakların kullanımına ilişkin sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have any orientation towards non-university resources for its research and development activities.","2":"The institution has plans to create non-university resources and methods and support processes for the use of these resources. However, there are no applications made in line with these plans or they do not cover all areas.","3":"In order to continue the research and development activities of the institution in line with corporate goals, method and support plans have been created for the use of non-university resources and there are practices covering all areas. However, the results regarding the use of these resources and practices are not monitored.","4":"In order to continue research and development activities in line with institutional goals, the findings obtained from practices that support the use of non-university resources are systematically monitored and the monitoring results are evaluated together with stakeholders and precautions are taken.","5":"In order to continue research and development activities in line with institutional goals (research policy, goals, strategy), sustainable and mature practices regarding the use of non-university resources have been adopted and secured throughout the institution; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"ليس لدى المؤسسة أي توجه نحو الموارد غير الجامعية لأنشطتها البحثية والتطويرية.","2":"لدى المؤسسة خطط لإنشاء موارد وأساليب غير جامعية وعمليات دعم لاستخدام هذه الموارد. ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط أو أنها لا تغطي جميع المجالات.","3":"من أجل مواصلة أنشطة البحث والتطوير للمؤسسة بما يتماشى مع أهداف الشركة، تم إنشاء أساليب وخطط دعم لاستخدام الموارد غير الجامعية وهناك ممارسات تغطي جميع المجالات. ومع ذلك، لا يتم رصد النتائج المتعلقة باستخدام هذه الموارد والممارسات.","4":"من أجل مواصلة أنشطة البحث والتطوير بما يتماشى مع الأهداف المؤسسية، تتم مراقبة النتائج التي تم الحصول عليها من الممارسات التي تدعم استخدام الموارد غير الجامعية بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"من أجل مواصلة أنشطة البحث والتطوير بما يتماشى مع الأهداف المؤسسية (سياسة البحث والأهداف والاستراتيجية)، تم اعتماد وتأمين ممارسات مستدامة وناضجة فيما يتعلق باستخدام الموارد غير الجامعية في جميع أنحاء المؤسسة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (46, 'C.2.4', 'Kurumun Araştırma Politikası ve Uyumlu Lisansüstü Programlar', 'Institution''s Research Policy and Compatible Graduate Programs', 'السياسة البحثية للمؤسسة وبرامج الدراسات العليا المتوافقة', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun araştırma politikası, hedefleri, stratejisi ile uyumlu lisansüstü programlar bulunmamaktadır.","2":"Kurumun araştırma politikası, hedefleri ve stratejileri ile uyumlu lisansüstü programlara ilişkin planlar ve tanımlı süreçler bulunmaktadır. Ancak bu planlar ve süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamamaktadır.","3":"Kurumda araştırma politikası, hedefleri ve stratejiler i ile uyumlu ve destekleyen lisansüstü programlar yürütülmektedir. Ancak bu uygulamaların sonuçları izlenmemektedir.","4":"Kurumda araştırma politikası, hedefleri ve stratejileri ile uyumlu ve destekleyen lisansüstü programların çıktıları düzenli olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda, araştırma ve geliştirme faaliyetlerini kurumsal amaçlar (araştırma politikası, hedefleri, stratejisi) doğrultusunda sürdürebilmek için lisansüstü programlara ilişkin bütünleşik ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no graduate programs compatible with the institution''s research policy, goals and strategy.","2":"There are plans and defined processes for graduate programs that are compatible with the institution''s research policy, goals and strategies. However, there are no practices made in line with these plans and processes or they do not cover all areas.","3":"The institution carries out postgraduate programs that are compatible with and support the research policy, goals and strategies. However, the results of these practices are not monitored.","4":"The outputs of graduate programs that are compatible with and support the institution''s research policy, goals and strategies are regularly monitored, and the monitoring results are evaluated together with stakeholders and precautions are taken.","5":"In order to continue research and development activities in line with institutional goals (research policy, objectives, strategy), integrated and mature practices regarding postgraduate programs have been adopted and secured throughout the institution; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد برامج دراسات عليا متوافقة مع السياسة البحثية للمؤسسة وأهدافها واستراتيجيتها.","2":"هناك خطط وعمليات محددة لبرامج الدراسات العليا تتوافق مع السياسة البحثية للمؤسسة وأهدافها واستراتيجياتها. ومع ذلك، لا توجد ممارسات تتماشى مع هذه الخطط والعمليات أو أنها لا تغطي جميع المجالات.","3":"تنفذ المؤسسة برامج الدراسات العليا التي تتوافق مع وتدعم سياسة البحث وأهدافه واستراتيجياته. ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"تتم مراقبة مخرجات برامج الدراسات العليا المتوافقة مع السياسة البحثية للمؤسسة وأهدافها واستراتيجياتها وتدعمها بانتظام، ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"من أجل مواصلة أنشطة البحث والتطوير بما يتماشى مع الأهداف المؤسسية (سياسة البحث والأهداف والاستراتيجية)، تم اعتماد وتأمين الممارسات المتكاملة والناضجة فيما يتعلق ببرامج الدراسات العليا في جميع أنحاء المؤسسة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (47, 'C.3.1', 'Öğretim Elemanlarının Araştırma Yetkinliğinin Geliştirilmesi', 'Improving the Research Competency of Faculty Members', 'تحسين الكفاءة البحثية لأعضاء هيئة التدريس', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda, öğretim elemanlarının araştırma yetkinliğinin (uzmanlıklar, birikim, sayı ve dağılım) değerlendirilmesine ve geliştirilmesine yönelik bir mekanizma bulunmamaktadır.","2":"Kurumda, öğretim elemanlarının araştırma yetkinliğinin değerlendirilmesine ve geliştirilmesine yönelik planlar ve tanımlı süreçler bulunmaktadır. Ancak bu planlar ve süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamayan uygulamalar bulunm aktadır.","3":"Kurumda, öğretim elemanlarının araştırma yetkinliğinin değerlendirilmesine ve geliştirilmesine yönelik uygulamalar tüm alanları kapsayan şekilde yürütülmektedir. Ancak bu uygulamaların sonuçları izlenmemektedir.","4":"Kurumda, öğretim elemanlarının araştırma yetkinliğinin değerlendirilmesine ve geliştirilmesine yönelik uygulamalar düzenli olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda, kurumsal amaçlar (araştırma politikası, hedefleri, stratejisi) doğrultusunda öğretim elemanlarının araştırma yetkinliğinin değerlendirilmesi ve geliştirilmesine ilişkin sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun kendine özgü ve yenilikçi birçok uygu laması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have a mechanism for evaluating and developing the research competence of faculty members (specialties, background, number and distribution).","2":"The institution has plans and defined processes for evaluating and developing the research competence of faculty members. However, there are no practices made in line with these plans and processes, or there are practices that do not cover all areas.","3":"In the institution, practices aimed at evaluating and developing the research competence of faculty members are carried out in a way that covers all areas. However, the results of these practices are not monitored.","4":"In the institution, practices aimed at evaluating and developing the research competence of faculty members are regularly monitored, and the monitoring results are evaluated together with stakeholders and precautions are taken.","5":"In the institution, sustainable and mature practices regarding the evaluation and development of faculty members'' research competence in line with institutional goals (research policy, goals, strategy) have been adopted and secured throughout the institution; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد لدى المؤسسة آلية لتقييم وتطوير الكفاءة البحثية لأعضاء هيئة التدريس (التخصصات والخلفية والعدد والتوزيع).","2":"لدى المؤسسة خطط وعمليات محددة لتقييم وتطوير الكفاءة البحثية لأعضاء هيئة التدريس. ومع ذلك، لا توجد ممارسات تتماشى مع هذه الخطط والعمليات، أو أن هناك ممارسات لا تغطي جميع المجالات.","3":"في المؤسسة، يتم تنفيذ الممارسات التي تهدف إلى تقييم وتطوير الكفاءة البحثية لأعضاء هيئة التدريس بطريقة تغطي جميع المجالات. ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"في المؤسسة، تتم مراقبة الممارسات التي تهدف إلى تقييم وتطوير الكفاءة البحثية لأعضاء هيئة التدريس بانتظام، ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"في المؤسسة، تم اعتماد وتأمين ممارسات مستدامة وناضجة فيما يتعلق بتقييم وتطوير الكفاءة البحثية لأعضاء هيئة التدريس بما يتماشى مع الأهداف المؤسسية (سياسة البحث، والأهداف، والاستراتيجية) في جميع أنحاء المؤسسة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (48, 'C.3.2', 'Ulusal ve Uluslararası Araştırma Birimleri ile Ortak Programlar', 'Joint Programs with National and International Research Units', 'برامج مشتركة مع وحدات البحوث الوطنية والدولية', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda ulusal ve uluslararası düzeyde kurum içi ve kurumlar arası ortak programlar ve ortak araştırma birimleri ile araştırma ağlarına katılım ve işbirlikleri kurma gibi çoklu araştırma faaliyetleri bulunmamaktadır.","2":"Kurumda ulusal ve uluslararası düzeyde kurum içi ve kurumlar arası ortak programlar ve ortak araştırma birimleri ile ara ştırma ağlarına katılım ve işbirlikleri kurma gibi çoklu araştırma faaliyetlerine yönelik planlamalar ve tanımlı süreçler bulunmaktadır. Ancak bu planlar ve süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır.","3":"Kurumda ulusal ve uluslararası düzeyde kurum içi ve kurumlar arası ortak programlar ve ortak araştırma birimleri ile araştırma ağlarına katılım ve işbirlikleri kurma gibi çoklu araştırma faaliyetleri ve uygulamalar tüm alanlarda yürütülmektedir. Ancak bu uygulamaların sonuçları izlenmemektedir.","4":"Kurumda ulusal ve uluslararası düzeyde kurum içi ve kurumlar arası ortak programlar ve ortak araştırma birimleri ile araştırma ağlarına katılım ve işbirlikleri kurma gibi çoklu araştırma faaliyetleri ve uygulamalar düzenli olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda, kurumsal amaçlar (araştırma politikası, hedefleri, stratejisi) doğrultusunda kurum içi ve kurumlar arası, ulusal ve uluslararası düzeyde ortak programlar ve ortak araştırma birim leri, işbirlikleri ve araştırma ağlarına katılım gibi çoklu araştırma faaliyetlerine ve uygulamalarına ilişkin sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun kendine özgü ve yenilikçi birçok uy gulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have multiple research activities such as intra-institutional and inter-institutional joint programs and joint research units at national and international levels, as well as participation in research networks and establishing collaborations.","2":"The institution has plans and defined processes for multiple research activities such as intra-institutional and inter-institutional joint programs and participation in research networks with joint research units and establishing collaborations at national and international levels. However, there are no practices made in line with these plans and processes.","3":"Multiple research activities and practices are carried out in all areas of the institution, such as participating in research networks and establishing collaborations with intra-institutional and inter-institutional joint programs and joint research units at national and international levels. However, the results of these practices are not monitored.","4":"Multiple research activities and practices, such as participation in research networks and establishing collaborations with intra-institutional and inter-institutional joint programs and joint research units at national and international levels, are regularly monitored in the institution, and the monitoring results are evaluated together with stakeholders and precautions are taken.","5":"In the institution, sustainable and mature practices regarding multiple research activities and practices, such as joint programs and joint research units, collaborations and participation in research networks at intra- and inter-institutional, national and international levels, in line with institutional objectives (research policy, objectives, strategy) have been adopted and secured throughout the institution; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"ليس لدى المؤسسة أنشطة بحثية متعددة مثل البرامج المشتركة داخل المؤسسات وبين المؤسسات ووحدات البحث المشتركة على المستويين الوطني والدولي، فضلا عن المشاركة في شبكات البحث وإقامة التعاون.","2":"لدى المؤسسة خطط وعمليات محددة لأنشطة بحثية متعددة مثل البرامج المشتركة بين المؤسسات وبين المؤسسات والمشاركة في شبكات البحث مع وحدات بحثية مشتركة وإقامة علاقات تعاون على المستويين الوطني والدولي. ومع ذلك، لا توجد ممارسات تتماشى مع هذه الخطط والعمليات.","3":"يتم تنفيذ أنشطة وممارسات بحثية متعددة في جميع مجالات المؤسسة، مثل المشاركة في شبكات البحث وإقامة علاقات تعاون مع البرامج المشتركة داخل المؤسسات وفيما بين المؤسسات ووحدات البحث المشتركة على المستويين الوطني والدولي. ومع ذلك، لا يتم رصد نتائج هذه الممارسات.","4":"تتم مراقبة الأنشطة والممارسات البحثية المتعددة، مثل المشاركة في شبكات البحث وإقامة علاقات تعاون مع البرامج المشتركة داخل المؤسسات وفيما بين المؤسسات ووحدات البحث المشتركة على المستويين الوطني والدولي، بانتظام في المؤسسة، ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"في المؤسسة، تم اعتماد ممارسات مستدامة وناضجة فيما يتعلق بالأنشطة والممارسات البحثية المتعددة، مثل البرامج المشتركة ووحدات البحث المشتركة والتعاون والمشاركة في شبكات البحث على المستويات داخل المؤسسات وفيما بينها وعلى المستوى الوطني والدولي، بما يتماشى مع الأهداف المؤسسية (سياسة البحث والأهداف والاستراتيجية) وتأمينها في جميع أنحاء المؤسسة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (49, 'C.4.1', 'Öğretim Elemanı Performans Değerlendirmesi', 'Instructor Performance Evaluation', 'تقييم أداء المعلم', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda öğretim elemanlarının araştırma performansının izlenmesine ve değerlendirmesine yönelik uygulamalar bulunmamaktadır.","2":"Kurumda öğretim elemanlarının araştırma performansının izlenmesine ve değerlendirmesine yönelik planlamalar ve tanımlı süreçler (yönetmelik, yönerge, süreç tanımı, ölçme araçları, rehber, kılavuz, takdirtanıma sistemi, teşvik mekanizmaları vb.) bulunmaktadır. Ancak bu planlar ve süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamayan uygulamalar bulunmaktadır.","3":"Öğretim elemanlarının araştırma-geliştirme performansını izlemek ve değerlendirmek üzere tanımlı süreçler (yönetmelik, yönerge, süreç tanımı, ölçme araçları, rehber, kılavuz, takdir-tanıma sistemi, teşvik mekanizmaları vb.) tüm alanları kapsar şekilde yürütülmektedir. Ancak bu uygulamaların sonuçları izlenmemektedir veya karar almalarda kullanılmamaktadır.","4":"Öğretim elemanlarının araştırmageliştirme performansını izlemek ve değerlendirmek üzere tüm alanları kapsayan uygulamalar düzenli olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda, kurumsal amaçlar (araştırma politikası, hedefleri, stratejisi) doğrultusunda öğretim elemanlarının araştırma-geliştirme performansının izlenmesi ve değerlendirilmesine ilişkin sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no practices in the institution for monitoring and evaluating the research performance of faculty members.","2":"The institution has plans and defined processes for monitoring and evaluating the research performance of faculty members (regulation, directive, process definition, measurement tools, guide, guide, recognition system, incentive mechanisms, etc.). However, there are no applications made in line with these plans and processes, or there are applications that do not cover all areas.","3":"Defined processes to monitor and evaluate the research and development performance of faculty members (regulation, directive, process definition, measurement tools, guide, guide, appreciation-recognition system, incentive mechanisms, etc.) are carried out in a way that covers all areas. However, the results of these applications are not monitored or used in decision-making.","4":"In order to monitor and evaluate the research and development performance of faculty members, practices covering all areas are monitored regularly and the monitoring results are evaluated together with stakeholders and precautions are taken.","5":"In the institution, sustainable and mature practices regarding the monitoring and evaluation of the research and development performance of faculty members in line with institutional objectives (research policy, objectives, strategy) have been adopted and secured throughout the institution; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد ممارسات في المؤسسة لمراقبة وتقييم الأداء البحثي لأعضاء هيئة التدريس.","2":"لدى المؤسسة خطط وعمليات محددة لمراقبة وتقييم الأداء البحثي لأعضاء هيئة التدريس (التنظيم، التوجيه، تعريف العملية، أدوات القياس، الدليل، المرشد، نظام الاعتراف، آليات الحوافز، إلخ). ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط والعمليات، أو هناك طلبات لا تغطي جميع المجالات.","3":"يتم تنفيذ العمليات المحددة لمراقبة وتقييم الأداء البحثي والتطوير لأعضاء هيئة التدريس (التنظيم، التوجيه، تعريف العمليات، أدوات القياس، الدليل، الدليل، نظام التقدير والتقدير، آليات الحوافز، وما إلى ذلك) بطريقة تغطي جميع المجالات. ومع ذلك، لا يتم رصد نتائج هذه التطبيقات أو استخدامها في اتخاذ القرار.","4":"من أجل مراقبة وتقييم أداء البحث والتطوير لأعضاء هيئة التدريس، تتم مراقبة الممارسات التي تغطي جميع المجالات بانتظام ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"في المؤسسة، تم اعتماد وتأمين ممارسات مستدامة وناضجة فيما يتعلق برصد وتقييم أداء البحث والتطوير لأعضاء هيئة التدريس بما يتماشى مع الأهداف المؤسسية (سياسة البحث والأهداف والاستراتيجية) في جميع أنحاء المؤسسة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (50, 'C.4.2', 'Araştırma Performansının Değerlendirilmesi ve İyileştirilmesi', 'Evaluation and Improvement of Research Performance', 'تقييم وتحسين أداء البحث', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda araştırma performansının izlenmesine ve değerlendirmesine yönelik uygulamalar bulunmamaktadır.","2":"Kurumda araştırma performansının izlenmesine ve değerlendirmesine yönelik planlamalar ve tanımlı süreçler bulunmaktadır. Ancak bu planlar ve süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamayan uygulamalar bulunmaktadır.","3":"Kurumda araştırma performansının izlenmesine ve değerlendirmesine yönelik uygulamalar tüm alanları kapsar şekilde yürütülmektedir. Ancak bu uygulamaların sonuçları izlenmemektedir veya karar almalarda kullanılmamaktadır.","4":"Kurumda tüm alanların araştırma performansı izlenerek değerlendirilmekte ve karar almalarda (performans temelli teşvik-takdir mekanizmaları vb.) kullanılmaktadır. Buna ilişkin uygulamalar düzenli olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda, kurumsal amaçlar (araştırma politikası, hedefleri, stratejisi) doğrultusunda tüm alanların araştırma performansının izlenmesi ve değerlendirilmesine ilişkin sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no practices for monitoring and evaluating research performance in the institution.","2":"The institution has plans and defined processes for monitoring and evaluating research performance. However, there are no applications made in line with these plans and processes, or there are applications that do not cover all areas.","3":"Practices for monitoring and evaluating research performance in the institution are carried out in a way that covers all areas. However, the results of these applications are not monitored or used in decision-making.","4":"The research performance of all areas in the institution is monitored and evaluated and used in decision-making (performance-based incentive-appreciation mechanisms, etc.). Related practices are monitored regularly and the monitoring results are evaluated together with stakeholders and precautions are taken.","5":"In the institution, sustainable and mature practices for monitoring and evaluating the research performance of all areas in line with institutional objectives (research policy, objectives, strategy) have been adopted and secured throughout the institution; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد ممارسات لمراقبة وتقييم الأداء البحثي في ​​المؤسسة.","2":"لدى المؤسسة خطط وعمليات محددة لرصد وتقييم الأداء البحثي. ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط والعمليات، أو هناك طلبات لا تغطي جميع المجالات.","3":"يتم تنفيذ ممارسات مراقبة وتقييم الأداء البحثي في ​​المؤسسة بطريقة تغطي جميع المجالات. ومع ذلك، لا يتم رصد نتائج هذه التطبيقات أو استخدامها في اتخاذ القرار.","4":"يتم مراقبة وتقييم الأداء البحثي في ​​جميع المجالات في المؤسسة واستخدامه في اتخاذ القرار (آليات تقدير الحوافز القائمة على الأداء، وما إلى ذلك). تتم مراقبة الممارسات ذات الصلة بانتظام ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"في المؤسسة، تم اعتماد وتأمين ممارسات مستدامة وناضجة لرصد وتقييم الأداء البحثي في ​​جميع المجالات بما يتماشى مع الأهداف المؤسسية (سياسة البحث، والأهداف، والاستراتيجية) في جميع أنحاء المؤسسة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (51, 'C.4.3', 'Araştırma Bütçe Performansı', 'Research Budget Performance', 'أداء ميزانية البحث', 3, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun araştırma bütçe performansını izlemeye yönelik uygulamalar bulunmamaktadır.","2":"Kurumun araştırma bütçe performansını izlemeye ilişkin planlamalar ve tanımlı süreçler bulunmaktadır. Ancak bu planlar ve süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamayan uygulamalar bulunmaktadır.","3":"Kurumun araştırma bütçe performansını izlemeye ve değerlendirmeye ilişkin uygulamalar bulunmaktadır. Ancak bu uygulamaların sonuçları izlenmemektedir veya karar almalarda kullanılmamaktadır.","4":"Kurumun araştırma bütçe performansı izlenerek değerlendirilmekte ve karar almalarda (bütçe dağılımı vb.) kullanılmaktadır. Buna ilişkin uygulamalar düzenli olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda, kurumsal amaçlar (araştırma politikası, hedefleri, stratejisi) doğrultusunda tüm birimlerin araştırma bütçe performansının izlenmesi ve değerlendirilmesine ilişkin sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no applications for monitoring the institution''s research budget performance.","2":"There are plans and defined processes for monitoring the institution''s research budget performance. However, there are no applications made in line with these plans and processes, or there are applications that do not cover all areas.","3":"There are practices for monitoring and evaluating the institution''s research budget performance. However, the results of these applications are not monitored or used in decision-making.","4":"The research budget performance of the institution is monitored and evaluated and used in decision-making (budget distribution, etc.). Related practices are monitored regularly and the monitoring results are evaluated together with stakeholders and precautions are taken.","5":"In the institution, sustainable and mature practices regarding the monitoring and evaluation of the research budget performance of all units in line with institutional objectives (research policy, objectives, strategy) have been adopted and secured throughout the institution; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد طلبات لمراقبة أداء ميزانية البحث في المؤسسة.","2":"هناك خطط وعمليات محددة لمراقبة أداء ميزانية البحث في المؤسسة. ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط والعمليات، أو هناك طلبات لا تغطي جميع المجالات.","3":"هناك ممارسات لرصد وتقييم أداء ميزانية البحث في المؤسسة. ومع ذلك، لا يتم رصد نتائج هذه التطبيقات أو استخدامها في اتخاذ القرار.","4":"يتم مراقبة وتقييم أداء ميزانية البحث للمؤسسة واستخدامها في اتخاذ القرار (توزيع الميزانية، وما إلى ذلك). تتم مراقبة الممارسات ذات الصلة بانتظام ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"في المؤسسة، تم اعتماد وتأمين ممارسات مستدامة وناضجة فيما يتعلق برصد وتقييم أداء ميزانية البحث لجميع الوحدات بما يتماشى مع الأهداف المؤسسية (سياسة البحث، والأهداف، والاستراتيجية) في جميع أنحاء المؤسسة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (52, 'D.1.1', 'Toplumsal Katkı Politikası, Hedefleri ve Stratejisi', 'Social Contribution Policy, Goals and Strategy', 'سياسة المساهمة الاجتماعية والأهداف والاستراتيجية', 4, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun tanımlı toplumsal katkı politikası, hedefleri ve stratejisi bulunmamaktadır.","2":"Kurumun, toplumsal katkı faaliyetlerinde izleyeceği ilkeleri, öncelikleri ve kaynaklarını yönetmedeki tercihlerini ifade eden toplumsal katkı politikası, hedefleri ve stratejisi bulunmaktadır. Ancak bunları hayata geçirmek üzere mekanizmalar veya uygulamalar bulunmamaktadır.","3":"Kurumun tanımlı toplumsal katkı pol itikası, hedefleri ve stratejisi doğrultusunda yapılan uygulamalar bulunmaktadır. Ancak bu uygulamaların sonuçları değerlendirilmemektedir.","4":"Kurumun tamamı tarafından benimsenmiş toplumsal katkı politikası, hedefleri ve stratejisi ile ilgili uygulamalar, si stematik olarak izlenmekte ve izlem sonuçlarına göre tüm alanları kapsayan önlemler alınmaktadır.","5":"Kurumda toplumsal katkı faaliyetlerinin, toplumsal katkı politikası doğrultusunda değer üretebilmesi ve toplumsal faydaya dönüşebilmesi güvence altına alınmış ve olgunlaşmış uygulamalarla paydaşlarca benimsenmesi sağlanmıştır; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have a defined social contribution policy, goals and strategy.","2":"The institution has a social contribution policy, goals and strategy, which express the principles, priorities and preferences it will follow in its social contribution activities and its preferences in managing its resources. However, there are no mechanisms or practices to implement these.","3":"There are practices carried out in line with the institution''s defined social contribution policy, goals and strategy. However, the results of these applications are not evaluated.","4":"Practices related to the social contribution policy, objectives and strategy adopted by the entire institution are systematically monitored and measures covering all areas are taken according to the monitoring results.","5":"It is ensured that social contribution activities in the institution can produce value and turn into social benefit in line with the social contribution policy, and that they are adopted by stakeholders with mature practices; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"ليس لدى المؤسسة سياسة وأهداف واستراتيجية محددة للمساهمة الاجتماعية.","2":"لدى المؤسسة سياسة وأهداف واستراتيجية للمساهمة الاجتماعية، والتي تعبر عن المبادئ والأولويات والتفضيلات التي ستتبعها في أنشطة المساهمة الاجتماعية وتفضيلاتها في إدارة مواردها. لكن لا توجد آليات أو ممارسات لتنفيذها.","3":"هناك ممارسات يتم تنفيذها بما يتماشى مع سياسة المساهمة الاجتماعية المحددة للمؤسسة وأهدافها واستراتيجيتها. ومع ذلك، لا يتم تقييم نتائج هذه التطبيقات.","4":"تتم مراقبة الممارسات المتعلقة بسياسة المساهمة الاجتماعية وأهدافها وإستراتيجيتها التي تتبناها المؤسسة بأكملها بشكل منهجي ويتم اتخاذ التدابير التي تغطي جميع المجالات وفقًا لنتائج المراقبة.","5":"التأكد من أن أنشطة المساهمة الاجتماعية في المؤسسة يمكن أن تنتج قيمة وتتحول إلى منفعة اجتماعية بما يتماشى مع سياسة المساهمة الاجتماعية، وأن يتم اعتمادها من قبل أصحاب المصلحة ذوي الممارسات الناضجة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (53, 'D.1.2', 'Toplumsal Katkı Süreçlerinin Yönetimi ve Teşkilat Yapısı', 'Management and Organizational Structure of Social Contribution Processes', 'الإدارة والهيكل التنظيمي لعمليات المساهمة الاجتماعية', 4, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun toplumsal katkı süreçlerinin yönetimi ve organizasyonel yapısına ilişkin bir planlaması bulunmamaktadır.","2":"Kurumun toplumsal katkı süreçlerinin, yerel, bölgesel ve ulusal ihtiyaç ve talepler ile ilişkili ve diğer süreçlerle (eğitimöğretim, araştırma-geliştirme) bütünleşik olarak yönetimi ve organizasyonel yapılanması (süreçler ve görev tanımları vb.) yönelik planlar bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamayan uygulamalar bulunmaktadır.","3":"Fakültede toplumsal katkı süreçlerinin yönetimi ve organizasyonel yapılanması kurumsal tercihler yönünde ve tüm alanları kapsayıcı şekilde uygulamaya konularak bazı sonuçlar elde edilmiştir. Ancak bu sonuçlar izlenmemektedir.","4":"Kurumda toplumsal katkı süreçlerinin yönetimi ile ilişkili sonuçlar ve paydaş görüşleri sistematik ve kurumun iç kalite güvence sistemiyle uyumlu olarak izlenmekte ve paydaşlarla birlikte değerlendirilerek önlem alınmaktadır.","5":"Kurumda tüm alanları kapsayan toplumsal katkı süreçlerinin yönetimi kurumsal amaçlar doğrultusunda bütünleştirici, sürdürülebilir ve olgunlaşmış uygulamalarla kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have a plan regarding the management and organizational structure of social contribution processes.","2":"There are plans for the management and organizational structuring (processes and job descriptions, etc.) of the institution''s social contribution processes in relation to local, regional and national needs and demands and integrated with other processes (education, research and development). However, there are no applications made in line with these plans, or there are applications that do not cover all areas.","3":"Some results have been achieved by implementing the management and organizational structuring of social contribution processes at the faculty in line with institutional preferences and in a way that covers all areas. However, these results are not monitored.","4":"The results and stakeholder opinions related to the management of social contribution processes in the institution are monitored systematically and in accordance with the internal quality assurance system of the institution, and measures are taken by evaluating them together with the stakeholders.","5":"The management of social contribution processes covering all areas in the institution has been adopted and secured throughout the institution with integrative, sustainable and mature practices in line with corporate goals; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"ليس لدى المؤسسة خطة فيما يتعلق بالإدارة والهيكل التنظيمي لعمليات المساهمة الاجتماعية.","2":"توجد خطط للإدارة والهيكل التنظيمي (العمليات والتوصيف الوظيفي، وما إلى ذلك) لعمليات المساهمة الاجتماعية للمؤسسة فيما يتعلق بالاحتياجات والمتطلبات المحلية والإقليمية والوطنية ومتكاملة مع العمليات الأخرى (التعليم والبحث والتطوير). ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط، أو هناك طلبات لا تغطي جميع المجالات.","3":"وقد تم تحقيق بعض النتائج من خلال تنفيذ الإدارة والهيكلة التنظيمية لعمليات المساهمة الاجتماعية في الكلية بما يتماشى مع التفضيلات المؤسسية وبطريقة تغطي جميع المجالات. ومع ذلك، لا يتم رصد هذه النتائج.","4":"تتم مراقبة النتائج وآراء أصحاب المصلحة المتعلقة بإدارة عمليات المساهمة الاجتماعية في المؤسسة بشكل منهجي ووفقًا لنظام ضمان الجودة الداخلي للمؤسسة، ويتم اتخاذ التدابير من خلال تقييمها مع أصحاب المصلحة.","5":"تم اعتماد إدارة عمليات المساهمة الاجتماعية التي تغطي جميع المجالات في المؤسسة وتأمينها في جميع أنحاء المؤسسة بممارسات متكاملة ومستدامة وناضجة بما يتماشى مع أهداف الشركة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (54, 'D.2', 'Toplumsal Katkı Kaynakları', 'Social Contribution Sources', 'مصادر المساهمة الاجتماعية', 4, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun toplumsal katkı faaliyetlerini sürdürebilmesi için uygun nitelik ve nicelikte fizik i, teknik ve mali kaynakları bulunmamaktadır.","2":"Kurumun toplumsal katkı faaliyetlerini sürdürebilmek için uygun nitelik ve nicelikte fiziki, teknik ve mali kaynakların oluşturulmasına yönelik planlar bulunmaktadır. Ancak bu planlar doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamayan uygulamalar bulunmaktadır.","3":"Kurumun toplumsal katkı faaliyetlerini sürdürebilmek için uygun nitelik ve nicelikte fiziki, teknik ve mali kaynaklar sağlanmaktadır. Ancak bu kaynakların kullanımına yönelik sonuçlar izlenmemektedir.","4":"Kurumda fiziki, teknik ve mali kaynaklar, toplumsal katkı faaliyetlerini destekleyecek ve tüm alanları kapsayacak şekilde yönetilmektedir. Tüm bu uygulamalardan elde edilen bulgular, sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar/talepler doğrultusunda kaynaklar çeşitlendirilmektedir.","5":"Kurumdaki uygun nicelik ve nitelikte fiziki, teknik ve mali kaynaklar, kurumsal amaçlar (toplumsal katkı hedefleri ve stratejisi) doğrultusunda ve sürdürülebilir şekilde yönetilmektedir; kurumun bu kapsamda kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have physical, technical and financial resources of appropriate quality and quantity to continue its social contribution activities.","2":"There are plans to create physical, technical and financial resources of appropriate quality and quantity in order to continue the institution''s social contribution activities. However, there are no applications made in line with these plans, or there are applications that do not cover all areas.","3":"Physical, technical and financial resources of appropriate quality and quantity are provided to sustain the institution''s social contribution activities. However, the results of the use of these resources are not monitored.","4":"The physical, technical and financial resources of the institution are managed in a way that supports social contribution activities and covers all areas. The findings obtained from all these applications are systematically monitored and the monitoring results are evaluated together with the stakeholders, precautions are taken and resources are diversified in line with the needs/demands.","5":"Physical, technical and financial resources of appropriate quantity and quality in the institution are managed in a sustainable manner in line with corporate objectives (social contribution targets and strategy); The institution has many unique and innovative applications in this context, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا تمتلك المؤسسة الموارد المادية والتقنية والمالية ذات الجودة والكمية المناسبة لمواصلة أنشطة المساهمة الاجتماعية.","2":"هناك خطط لإنشاء موارد مادية وتقنية ومالية ذات نوعية وكمية مناسبة من أجل مواصلة أنشطة المساهمة الاجتماعية للمؤسسة. ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط، أو هناك طلبات لا تغطي جميع المجالات.","3":"يتم توفير الموارد المادية والتقنية والمالية ذات الجودة والكمية المناسبة لدعم أنشطة المساهمة الاجتماعية للمؤسسة. ومع ذلك، لا يتم رصد نتائج استخدام هذه الموارد.","4":"تدار الموارد المادية والفنية والمالية للمؤسسة بما يدعم أنشطة المساهمة الاجتماعية ويغطي كافة المجالات. تتم مراقبة النتائج التي تم الحصول عليها من جميع هذه التطبيقات بشكل منهجي ويتم تقييم نتائج المراقبة مع أصحاب المصلحة، ويتم اتخاذ الاحتياطات وتنويع الموارد بما يتماشى مع الاحتياجات / المتطلبات.","5":"تتم إدارة الموارد المادية والتقنية والمالية ذات الكمية والنوعية المناسبة في المؤسسة بطريقة مستدامة بما يتماشى مع أهداف الشركة (أهداف واستراتيجيات المساهمة الاجتماعية)؛ وللمؤسسة العديد من التطبيقات الفريدة والمبتكرة في هذا السياق، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (55, 'D.3', 'Toplumsal Katkı Performansı', 'Social Contribution Performance', 'أداء المساهمة الاجتماعية', 4, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda toplumsal katkı performansının izlenmesine ve iyileştirilmesine yönelik uygulamalar bulunmamaktadır.","2":"Kurumda toplumsal katkı performansının izlenmesine ve iyileştirilmesine yönelik planlamalar ve tanımlı süreçler bulunmaktadır. Ancak bu planlar ve süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya tüm alanları kapsamayan uygulamalar bulunmaktadır.","3":"Kurumda toplumsal katkı performansının izlenmesine ve iyileştirilmesine yönelik uygulamalar tüm alanları kapsar şekilde yürütülmektedir. Ancak bu uygulamaların sonuçları izlenmemektedir veya karar almalarda kullanılmamaktadır.","4":"Kurumda tüm alanların toplumsal katkı performansı izlenerek değerlendirilmekte ve karar almalarda kullanılmaktadır. Buna ilişkin uygulamalar düzenli olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda, kurumsal amaçlar (toplumsal katkı politikası, hedefleri, stratejisi) doğrultusunda tüm alanların toplumsal katkı performansının izlenmesi ve değerlendirilmesine ilişkin sürdürülebilir ve olgunlaşmış uygulamalar kurumun tamamında benimsenmiş ve güvence altına alınmıştır; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no practices in the institution to monitor and improve social contribution performance.","2":"The institution has plans and defined processes for monitoring and improving social contribution performance. However, there are no applications made in line with these plans and processes, or there are applications that do not cover all areas.","3":"Practices aimed at monitoring and improving social contribution performance in the institution are carried out in a way that covers all areas. However, the results of these applications are not monitored or used in decision-making.","4":"The social contribution performance of all areas in the institution is monitored and evaluated and used in decision-making. Related practices are monitored regularly and the monitoring results are evaluated together with stakeholders and precautions are taken.","5":"In the institution, sustainable and mature practices regarding monitoring and evaluating the social contribution performance of all areas in line with corporate objectives (social contribution policy, goals, strategy) have been adopted and secured throughout the institution; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد ممارسات في المؤسسة لمراقبة وتحسين أداء المساهمة الاجتماعية.","2":"لدى المؤسسة خطط وعمليات محددة لرصد وتحسين أداء المساهمة الاجتماعية. ومع ذلك، لا توجد طلبات تتماشى مع هذه الخطط والعمليات، أو هناك طلبات لا تغطي جميع المجالات.","3":"يتم تنفيذ الممارسات التي تهدف إلى مراقبة وتحسين أداء المساهمة الاجتماعية في المؤسسة بطريقة تغطي جميع المجالات. ومع ذلك، لا يتم رصد نتائج هذه التطبيقات أو استخدامها في اتخاذ القرار.","4":"يتم مراقبة وتقييم أداء المساهمة الاجتماعية لجميع المجالات في المؤسسة واستخدامه في اتخاذ القرار. تتم مراقبة الممارسات ذات الصلة بانتظام ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"في المؤسسة، تم اعتماد وتأمين ممارسات مستدامة وناضجة فيما يتعلق برصد وتقييم أداء المساهمة الاجتماعية في جميع المجالات بما يتماشى مع أهداف الشركة (سياسة المساهمة الاجتماعية، والأهداف، والاستراتيجية) في جميع أنحاء المؤسسة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (56, 'E.1.1', 'Yönetim Modeli ve İdari Yapı', 'Management Model and Administrative Structure', 'نموذج الإدارة والهيكل الإداري', 5, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun misyonuyla uyumlu ve stratejik hedeflerini gerçekleştirmeyi sağlayacak bir yönetim modeli ve organizasyonel yapılanması bulunmamaktadır.","2":"Kurumun misyon ve stratejik hedeflerine ulaşmasını güvence altına alan yönetim modeli ve idari yapılanması; tüm süreçler tanımlanarak, süreçlerle uyumlu yetki, görev ve sorumluluklar belirlenerek tanımlanmıştır. Ancak bu model doğrultusunda yapılmış uygulamalar bulunmamaktadır veya uygulamalar tüm birimleri kapsamamaktadır.","3":"Kurumun misyon ve stratejik hedeflerine ulaşmasını güvence altına alan yönetim modeli ve idari yapılanması, süreçlerle uyumlu olarak ve tüm birimleri/alanları kapsayacak şekilde oluşturulmuştur ve bu doğrultuda yapılan uygulamalardan bazı sonuçlar elde edilmiştir. Ancak bu sonuçların izlenmesi yapılmamaktadır.","4":"Kurumda tüm birimleri ve alanları kapsayan yönetim modeli ve idari yapılanması ile ilişkili uygulamalardan elde edilen bulgular, sistematik olarak izlenmekte, paydaşların görüşleri alınmakta ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar/talepler doğrultusunda güncellemeler gerçekleştirilmektedir.","5":"Kurumda çok sesliliği, etkin karar vermeyi, değişime uyum sağlamayı ve paydaşların temsil edilmesini güvence altına alan ve kurumsal amaçların gerçekleştirilmesi için gerekli ortamı sağlayan yönetim modeli ve idari yapılanması (yasal düzenlemeler çerçevesinde kurumsal yaklaşım, gelenekler, tercihler) kurumun tamamında benimsenmiştir; kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have a management model and organizational structure that is compatible with its mission and will enable it to achieve its strategic goals.","2":"The management model and administrative structure that ensures that the institution achieves its mission and strategic goals; All processes are defined and the authorities, duties and responsibilities compatible with the processes are determined. However, there are no applications made in line with this model or the applications do not cover all units.","3":"The management model and administrative structuring that ensures that the institution achieves its mission and strategic goals has been created in accordance with the processes and covering all units/areas, and some results have been obtained from the practices carried out in this direction. However, these results are not monitored.","4":"The findings obtained from the practices related to the management model and administrative structure covering all units and areas in the institution are systematically monitored, the opinions of the stakeholders are taken and the monitoring results are evaluated together with the stakeholders, measures are taken and updates are made in line with the needs/demands.","5":"The management model and administrative structuring (institutional approach, traditions, preferences within the framework of legal regulations) that ensures polyphony, effective decision-making, adaptation to change and representation of stakeholders in the institution and provides the necessary environment for the realization of corporate goals are adopted throughout the institution; The institution has many unique and innovative applications, and some of these applications are taken as an example by other institutions."}'::jsonb, '{"1":"لا تمتلك المؤسسة نموذجاً إدارياً وهيكلاً تنظيمياً يتوافق مع رسالتها ويمكّنها من تحقيق أهدافها الاستراتيجية.","2":"النموذج الإداري والهيكل الإداري الذي يضمن تحقيق المؤسسة لرسالتها وأهدافها الاستراتيجية؛ يتم تحديد كافة العمليات وتحديد الصلاحيات والواجبات والمسؤوليات المتوافقة مع العمليات. ومع ذلك، لا توجد طلبات تتماشى مع هذا النموذج أو أن الطلبات لا تغطي جميع الوحدات.","3":"تم إنشاء نموذج الإدارة والهيكل الإداري الذي يضمن تحقيق المؤسسة لرسالتها وأهدافها الإستراتيجية وفقًا للعمليات ويغطي جميع الوحدات / المجالات، وتم الحصول على بعض النتائج من الممارسات التي تم تنفيذها في هذا الاتجاه. ومع ذلك، لا يتم رصد هذه النتائج.","4":"تتم مراقبة النتائج التي تم الحصول عليها من الممارسات المتعلقة بنموذج الإدارة والهيكل الإداري الذي يغطي جميع الوحدات والمجالات في المؤسسة بشكل منهجي، ويتم أخذ آراء أصحاب المصلحة ويتم تقييم نتائج المراقبة مع أصحاب المصلحة، ويتم اتخاذ التدابير وإجراء التحديثات بما يتماشى مع الاحتياجات / المتطلبات.","5":"نموذج الإدارة والهيكل الإداري (النهج المؤسسي والتقاليد والتفضيلات في إطار اللوائح القانونية) الذي يضمن تعدد الأصوات واتخاذ القرارات الفعالة والتكيف مع التغيير وتمثيل أصحاب المصلحة في المؤسسة ويوفر البيئة اللازمة لتحقيق الأهداف المؤسسية يتم اعتمادها في جميع أنحاء المؤسسة؛ تمتلك المؤسسة العديد من التطبيقات الفريدة والمبتكرة، وبعض هذه التطبيقات تتخذ مثالاً من قبل مؤسسات أخرى."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (57, 'E.1.2', 'Süreç Yönetimi', 'Process Management', 'إدارة العمليات', 5, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda eğitim öğretim, araştırma geliştirme, toplumsal katkı ve yönetim sistemine ilişkin süreçler tanımlanmamıştır.","2":"Kurumda eğitim öğretim, araştırmageliştirme, toplumsal katkı ve yönetim sistemine ilişkin süreçler tanımlanmıştır. Ancak uygulamalar bu süreçlerle uyumlu değildir veya tüm birimleri kapsamayan uygulamalar bulunmaktadır.","3":"Kurumda tüm birimleri ve alanları kapsayacak şekilde tüm süreçler tanımlanmıştır ve tüm uygulamalar süreçler doğrultusunda gerçekleştirilmektedir. Ancak süreç perf ormans sonuçları izlenmemekte veya süreç performans sonuçları karar almalarda kullanılmamaktadır.","4":"Kurumda tüm birimleri ve alanları kapsayacak şekilde yönetilen süreçlere ilişkin sonuçlar, performans göstergeleriyle sistematik olarak izlenmekte, paydaşları n görüşleri alınmakta ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar/talepler doğrultusunda güncellemeler gerçekleştirilmektedir.","5":"Kurumda stratejik hedeflerle uyumlu ve tüm alanları kapsayan süreç yönetim modeli sürdürülebilir ve olgunlaşmış uygulamalarla kurumun tamamında benimsenmiş ve güvence altına alınmıştır; bu hususta kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The processes related to education, research and development, social contribution and management system are not defined in the institution.","2":"Processes regarding education and training, research and development, social contribution and management system have been defined in the institution. However, applications are not compatible with these processes or there are applications that do not cover all units.","3":"All processes have been defined to cover all units and areas in the institution and all applications are carried out in line with the processes. However, process performance results are not monitored or process performance results are not used in decision making.","4":"The results of the processes managed to cover all units and areas in the institution are systematically monitored with performance indicators, the opinions of the stakeholders are taken and the monitoring results are evaluated together with the stakeholders, measures are taken and updates are made in line with the needs/demands.","5":"The process management model, which is compatible with strategic goals and covers all areas in the institution, has been adopted and secured throughout the institution with sustainable and mature practices; The institution has many unique and innovative practices in this regard, and some of these practices are taken as an example by other institutions."}'::jsonb, '{"1":"لم يتم تعريف العمليات المتعلقة بالتعليم والبحث والتطوير والمساهمة الاجتماعية ونظام الإدارة في المؤسسة.","2":"تم تحديد العمليات المتعلقة بالتعليم والتدريب والبحث والتطوير والمساهمة الاجتماعية ونظام الإدارة في المؤسسة. إلا أن التطبيقات غير متوافقة مع هذه العمليات أو أن هناك تطبيقات لا تغطي جميع الوحدات.","3":"تم تحديد جميع العمليات لتشمل جميع الوحدات والمجالات في المؤسسة ويتم تنفيذ جميع الطلبات بما يتماشى مع العمليات. ومع ذلك، لا تتم مراقبة نتائج أداء العملية أو لا يتم استخدام نتائج أداء العملية في اتخاذ القرار.","4":"تتم مراقبة نتائج العمليات المدارة لتغطية جميع الوحدات والمجالات في المؤسسة بشكل منهجي باستخدام مؤشرات الأداء، ويتم أخذ آراء أصحاب المصلحة ويتم تقييم نتائج المراقبة مع أصحاب المصلحة، ويتم اتخاذ التدابير وإجراء التحديثات بما يتماشى مع الاحتياجات / المتطلبات.","5":"إن نموذج إدارة العمليات، المتوافق مع الأهداف الإستراتيجية ويغطي جميع المجالات في المؤسسة، تم اعتماده وتأمينه في جميع أنحاء المؤسسة بممارسات مستدامة وناضجة؛ ولدى المؤسسة العديد من الممارسات الفريدة والمبتكرة في هذا الصدد، وبعض هذه الممارسات تتخذها مؤسسات أخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (58, 'E.2.1', 'İnsan Kaynakları Yönetimi', 'Human Resources Management', 'إدارة الموارد البشرية', 5, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda insan kaynakları yönetimine ilişkin tanımlı bir politika ve süreçler bulunmamaktadır.","2":"Kurumda insan kaynakları yönetimi politikası ile bununla uyumlu olarak tanımlanmış süreçleri bulunmaktadır. Ancak bunları hayata geçirmek üzere mekanizmalar veya uygulamalar bulunmamaktadır.","3":"Kurumun insan kaynakları politikası ve stratejik hedefleri ile uyumlu olarak, insan kaynakları süreçleri doğrultusunda uygulamalar bulunmaktadır ve bu uygulamalardan bazı sonuçlar elde edilmiştir. Ancak bu uygulamaların sonuçları izlenmemekte veya karar almalarda kullanılmamaktadır.","4":"Kurumda tüm birimleri kapsayan insan kaynakları yönetimi uygulamalarına ilişkin sonuçlar sistematik olarak izlenmekte, paydaş görüşleri alınmakta ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda stratejik hedeflerle uyumlu ve tüm alanları kapsayan insan kaynakları yönetim modeli sürdürülebilir ve olgunlaşmış uygulamalarla kurumun tamamında benimsenmiş ve güvence altına alınmıştır; bu hususta kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no defined policy and processes regarding human resources management in the institution.","2":"The institution has a human resources management policy and processes defined in accordance with it. However, there are no mechanisms or practices to implement these.","3":"In line with the human resources policy and strategic goals of the institution, there are practices in line with human resources processes and some results have been obtained from these practices. However, the results of these applications are not monitored or used in decision-making.","4":"The results of human resources management practices covering all units in the institution are systematically monitored, stakeholder opinions are received and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"The human resources management model, which is compatible with the strategic goals of the institution and covers all areas, has been adopted and secured throughout the institution with sustainable and mature practices; The institution has many unique and innovative practices in this regard, and some of these practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد سياسة وعمليات محددة فيما يتعلق بإدارة الموارد البشرية في المؤسسة.","2":"لدى المؤسسة سياسة وعمليات لإدارة الموارد البشرية محددة وفقًا لها. لكن لا توجد آليات أو ممارسات لتنفيذها.","3":"تماشياً مع سياسة الموارد البشرية والأهداف الإستراتيجية للمؤسسة، هناك ممارسات تتماشى مع عمليات الموارد البشرية وقد تم الحصول على بعض النتائج من هذه الممارسات. ومع ذلك، لا يتم رصد نتائج هذه التطبيقات أو استخدامها في اتخاذ القرار.","4":"تتم مراقبة نتائج ممارسات إدارة الموارد البشرية التي تغطي جميع الوحدات في المؤسسة بشكل منهجي، ويتم تلقي آراء أصحاب المصلحة ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"إن نموذج إدارة الموارد البشرية، المتوافق مع الأهداف الإستراتيجية للمؤسسة ويغطي كافة المجالات، تم اعتماده وتأمينه في جميع أنحاء المؤسسة بممارسات مستدامة وناضجة؛ ولدى المؤسسة العديد من الممارسات الفريدة والمبتكرة في هذا الصدد، وبعض هذه الممارسات تتخذها مؤسسات أخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (59, 'E.2.2', 'Finansal Kaynakların Yönetimi', 'Management of Financial Resources', 'إدارة الموارد المالية', 5, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda finansal kaynakların yönetimine ilişkin tanımlı süreçler bulunmamaktadır.","2":"Kurumda finansal kaynakların yönetimine ilişkin tanımlı süreçler bulunmaktadır. Ancak bu süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya mevcut uygulamalar tüm alanları kapsamamaktadır.","3":"Kurumun stratejik hedefleri ile uyumlu olarak, tanımlı süreçlere göre finansal kaynakların yönetimine ilişkin uygulamalar bulunmaktadır ve bu uygulamalardan bazı sonuçlar elde edilmiştir. Ancak bu uygulamaların sonuçları izlenmemekte veya karar almalarda kullanılmamaktadır.","4":"Kurumda tüm alanları kapsayacak şekilde yürütülen finansal kaynakların yönetimi uygulamalarına ilişkin sonuçlar sistematik olarak izlenmekte, paydaş görüşleri alınmakta ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumda stratejik hedeflerle uyumlu ve tüm alanları kapsayan finansal kaynakların yönetimi sürdürülebilir ve olgunlaşmış uygulamalarla kurumun tamamında benimsemiş ve güvence altına alınmıştır; bu hususta kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no defined processes for the management of financial resources in the institution.","2":"The institution has defined processes for the management of financial resources. However, there are no applications made in line with these processes or existing applications do not cover all areas.","3":"There are practices regarding the management of financial resources according to defined processes, in line with the strategic goals of the institution, and some results have been obtained from these practices. However, the results of these applications are not monitored or used in decision-making.","4":"The results of the financial resources management practices carried out in a way that covers all areas of the institution are systematically monitored, stakeholder opinions are received and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"The management of financial resources compatible with strategic goals and covering all areas in the institution has been adopted and secured throughout the institution with sustainable and mature practices; The institution has many unique and innovative practices in this regard, and some of these practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد عمليات محددة لإدارة الموارد المالية في المؤسسة.","2":"قامت المؤسسة بتحديد عمليات إدارة الموارد المالية. ومع ذلك، لا توجد طلبات تتماشى مع هذه العمليات أو أن التطبيقات الحالية لا تغطي جميع المجالات.","3":"هناك ممارسات تتعلق بإدارة الموارد المالية وفق عمليات محددة، بما يتماشى مع الأهداف الإستراتيجية للمؤسسة، وقد تم الحصول على بعض النتائج من هذه الممارسات. ومع ذلك، لا يتم رصد نتائج هذه التطبيقات أو استخدامها في اتخاذ القرار.","4":"تتم مراقبة نتائج ممارسات إدارة الموارد المالية التي يتم تنفيذها بطريقة تغطي جميع مجالات المؤسسة بشكل منهجي، ويتم تلقي آراء أصحاب المصلحة ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"تم اعتماد إدارة الموارد المالية المتوافقة مع الأهداف الإستراتيجية والتي تغطي جميع المجالات في المؤسسة وتأمينها في جميع أنحاء المؤسسة بممارسات مستدامة وناضجة؛ ولدى المؤسسة العديد من الممارسات الفريدة والمبتكرة في هذا الصدد، وبعض هذه الممارسات تتخذها مؤسسات أخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (60, 'E.3.1', 'Entegre Bilgi Yönetim Sistemi', 'Integrated Information Management System', 'نظام إدارة المعلومات المتكامل', 5, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda bilginin edinimi, saklanması ve kullanılmasına destek olacak herhangi bir bilişim sistemi bulunmamaktadır.","2":"Kurumda kurumsal bilginin edinimi, saklanması ve kullanılmasına destek olacak bilgi yönetim sistemleri bulunmaktadır. Ancak bu sistem bütünleşik değildir veya tüm alanları kapsamamaktadır.","3":"Kurumda tüm alanları kapsayan, tüm süreçleri destekleyen (eğitim-öğretim, araştırma-geliştirme, toplumsal katkı, kalite güvencesi) entegre bilgi yönetim sistemi bulunmaktadır ve bu sistemin kullanılması yönünde bazı uygulamalar bulunmaktadır. Ancak bilgi sistemi karar almalarda kullanılmamaktadır ve sistemin kullanımıyla ilgili sonuçlar izlenmemektedir.","4":"Kurumda tüm süreçleri destekleyen entegre bilgi yönetim sistemine ve kullanımına ilişkin sonuçlar sistematik olarak izlenmekte, paydaş görüşleri alınmakta ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmakta ve ihtiyaçlar/taleple doğrultusunda güncellemeler gerçekleştirilmektedir.","5":"Kurumsal amaçlar doğrultusunda sürdürülebilir ve olgunlaşmış entegre bilgi yönetim sistemi kurumun tamamında benimsenmiş ve güvence altına alınmıştır; bu hususta kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There is no information system in the institution to support the acquisition, storage and use of information.","2":"The institution has information management systems that will support the acquisition, storage and use of corporate information. However, this system is not integrated or does not cover all areas.","3":"The institution has an integrated information management system that covers all areas and supports all processes (education-training, research-development, social contribution, quality assurance), and there are some practices for using this system. However, the information system is not used in decision-making and the results of the use of the system are not monitored.","4":"The results regarding the integrated information management system and its use, which supports all processes in the institution, are systematically monitored, stakeholder opinions are received and the monitoring results are evaluated together with the stakeholders, measures are taken and updates are made in line with needs/demand.","5":"In line with corporate objectives, a sustainable and mature integrated information management system has been adopted and secured throughout the institution; The institution has many unique and innovative practices in this regard, and some of these practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا يوجد نظام معلومات في المؤسسة يدعم اكتساب المعلومات وتخزينها واستخدامها.","2":"تمتلك المؤسسة أنظمة إدارة معلومات من شأنها أن تدعم الحصول على معلومات الشركة وتخزينها واستخدامها. إلا أن هذا النظام ليس متكاملا أو لا يغطي كافة المجالات.","3":"تمتلك المؤسسة نظام متكامل لإدارة المعلومات يغطي جميع المجالات ويدعم جميع العمليات (التعليم والتدريب والبحث والتطوير والمساهمة الاجتماعية وضمان الجودة)، وهناك بعض الممارسات لاستخدام هذا النظام. ومع ذلك، لا يتم استخدام نظام المعلومات في اتخاذ القرارات ولا يتم مراقبة نتائج استخدام النظام.","4":"تتم مراقبة النتائج المتعلقة بنظام إدارة المعلومات المتكامل واستخدامه، والذي يدعم جميع العمليات في المؤسسة، بشكل منهجي، ويتم تلقي آراء أصحاب المصلحة ويتم تقييم نتائج المراقبة مع أصحاب المصلحة، ويتم اتخاذ التدابير وإجراء التحديثات بما يتماشى مع الاحتياجات / الطلب.","5":"تماشيًا مع أهداف الشركة، تم اعتماد وتأمين نظام متكامل ومستدام لإدارة المعلومات في جميع أنحاء المؤسسة؛ ولدى المؤسسة العديد من الممارسات الفريدة والمبتكرة في هذا الصدد، وبعض هذه الممارسات تتخذها مؤسسات أخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (61, 'E.3.2', 'Bilgi Güvenliği ve Güvenilirliği', 'Information Security and Reliability', 'أمن المعلومات والموثوقية', 5, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda bilgi güvenliği ve güvenirliğinin sağlanmasına ilişkin uygulamalar bulunmamaktadır.","2":"Kurumda bilgi güvenliği ve güvenirliğinin sağlanmasına yönelik tanımlı süreçler ve planlamalar bulunmaktadır. Ancak bu süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya uygulamalar tüm birimleri kapsamamaktadır.","3":"Kurumda bilgi güvenliği ve güvenirliğinin sağlanmasına yönelik bütünleşik uygulamalar bulunmakta ve bu uygulamalardan bazı sonuçlar elde edilmektedir. Ancak bu uygulamaların sonuçları izlenmemekte veya karar almalarda kullanılmamaktadır.","4":"Kurumda bilgi güvenliği ve güvenirliğinin sağlanmasına yönelik uygulamalar sistematik olarak izlenmekte ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumsal bilginin güvenliği ve güvenirliği sürdürülebilir ve olgunlaşmış uygulamalarla kurumun tamamında benimsenmiş ve güvence altına alınmıştır; bu hususta kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"There are no practices to ensure information security and reliability in the institution.","2":"The institution has defined processes and plans to ensure information security and reliability. However, there are no practices made in line with these processes or the practices do not cover all units.","3":"There are integrated applications to ensure information security and reliability in the institution, and some results are obtained from these applications. However, the results of these applications are not monitored or used in decision-making.","4":"Practices to ensure information security and reliability in the institution are systematically monitored, and the monitoring results are evaluated together with stakeholders and precautions are taken.","5":"The security and reliability of corporate information is adopted and guaranteed throughout the institution with sustainable and mature practices; The institution has many unique and innovative practices in this regard, and some of these practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا توجد ممارسات لضمان أمن وموثوقية المعلومات في المؤسسة.","2":"قامت المؤسسة بتحديد العمليات والخطط لضمان أمن المعلومات وموثوقيتها. ومع ذلك، لا توجد ممارسات تتماشى مع هذه العمليات أو أن الممارسات لا تغطي جميع الوحدات.","3":"توجد تطبيقات متكاملة لضمان أمن وموثوقية المعلومات في المؤسسة، ويتم الحصول على بعض النتائج من هذه التطبيقات. ومع ذلك، لا يتم رصد نتائج هذه التطبيقات أو استخدامها في اتخاذ القرار.","4":"تتم مراقبة ممارسات ضمان أمن المعلومات وموثوقيتها في المؤسسة بشكل منهجي، ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"يتم اعتماد وضمان أمن وموثوقية معلومات الشركة في جميع أنحاء المؤسسة من خلال ممارسات مستدامة وناضجة؛ ولدى المؤسسة العديد من الممارسات الفريدة والمبتكرة في هذا الصدد، وبعض هذه الممارسات تتخذها مؤسسات أخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (62, 'E.4.1', 'Hizmet ve Malların Uygunluğu, Kalitesi ve Sürekliliği', 'Suitability, Quality and Continuity of Services and Goods', 'الملاءمة والجودة واستمرارية الخدمات والسلع', 5, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumda, dışarıdan temin edilen malların ve destek hizmetlerinin uygunluğunu ve kalitesini değerlendirmek üzere tanımlı kriterler ve süreçler bulunmamaktadır.","2":"Kurumda, dışarıdan temin edilen destek hizmetlerinin ve malların uygunluğunu, kalitesini ve sürekliliğini güvence altına almak üzere bazı tanımlı süreçler ve mekanizmalar (tedarik süreci, uygunluk ve kalite kriterleri gibi) bulunmaktadır. Ancak bu süreçler doğrultusunda yapılan uygulamalar bulunmamaktadır veya uygulamalar tüm alanları kapsamamaktadır.","3":"Kurumda, dışarıdan temin edilen tüm mallardan ve destek hizmetlerinden beklenen kalite düzeylerinin iç kalite güvence sistemi kapsamında planlanması, değerlendirilip iyileştirilmesi yönünde uygulamalar gerçekleştirilmektedir. Ancak bu uygulamaların sonuçları izlenmemekte veya karar almalarda kullanılmamaktadır.","4":"Kurumda, dışarıdan tedarik edilen tüm hizmetlerin ve malların kalitesini güvence altına almak üzere tedarikçilerle yakın işbirlikleri yürütülmekte, tedarikçilerin performansı ve memnuniyetleri sistematik olarak izlenerek paydaşlarla birlikte değerlendirilmekte ve gerekli önlemler alınmaktadır.","5":"Kurumda dışarıdan temin edilen mal ve hizmetlerin kalite düzeylerini, kurumsal amaçlar doğrultusunda güvence altına almak üzere tedarik zinciri yönetilmektedir; bu hususta kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have defined criteria and processes to evaluate the suitability and quality of externally procured goods and support services.","2":"The institution has some defined processes and mechanisms (such as procurement process, compliance and quality criteria) to ensure the suitability, quality and continuity of outsourced support services and goods. However, there are no applications made in line with these processes or the applications do not cover all areas.","3":"In the institution, practices are carried out to plan, evaluate and improve the quality levels expected from all externally procured goods and support services within the scope of the internal quality assurance system. However, the results of these applications are not monitored or used in decision-making.","4":"The institution maintains close collaborations with suppliers to ensure the quality of all externally procured services and goods, the performance and satisfaction of suppliers are systematically monitored and evaluated together with stakeholders, and necessary precautions are taken.","5":"The supply chain is managed in the institution to ensure the quality levels of externally procured goods and services in line with corporate objectives; The institution has many unique and innovative practices in this regard, and some of these practices are taken as an example by other institutions."}'::jsonb, '{"1":"ليس لدى المؤسسة معايير وعمليات محددة لتقييم مدى ملاءمة وجودة السلع المشتراة من الخارج وخدمات الدعم.","2":"لدى المؤسسة بعض العمليات والآليات المحددة (مثل عملية الشراء والامتثال ومعايير الجودة) لضمان ملاءمة وجودة واستمرارية خدمات وسلع الدعم الخارجية. ومع ذلك، لا توجد طلبات تتماشى مع هذه العمليات أو أن الطلبات لا تغطي جميع المجالات.","3":"في المؤسسة، يتم تنفيذ الممارسات لتخطيط وتقييم وتحسين مستويات الجودة المتوقعة من جميع السلع المشتراة خارجيًا وخدمات الدعم ضمن نطاق نظام ضمان الجودة الداخلي. ومع ذلك، لا يتم رصد نتائج هذه التطبيقات أو استخدامها في اتخاذ القرار.","4":"تحافظ المؤسسة على تعاون وثيق مع الموردين لضمان جودة جميع الخدمات والسلع المشتراة من الخارج، ويتم مراقبة وتقييم أداء ورضا الموردين بشكل منهجي مع أصحاب المصلحة، ويتم اتخاذ الاحتياطات اللازمة.","5":"تتم إدارة سلسلة التوريد في المؤسسة لضمان مستويات جودة السلع والخدمات المشتراة من الخارج بما يتماشى مع أهداف الشركة؛ ولدى المؤسسة العديد من الممارسات الفريدة والمبتكرة في هذا الصدد، وبعض هذه الممارسات تتخذها مؤسسات أخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (63, 'E.5.1', 'Kamuoyunu Bilgilendirme', 'Public Information', 'المعلومات العامة', 5, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun faaliyetlerine ilişkin kamuoyunu bilgilendirmek üzere tanımlı ilkeleri ve mekanizmaları bulunmamaktadır.","2":"Kurum, faaliyetlerine ilişkin kamuoyunu bilgilendirmeyi ilkesel olarak benimsemek üzere bir politika tanımlamış, kamuoyunu bilgilendirme yöntem ve süreçlerini belirlemiştir. Ancak bu politika ve süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya uygulamalar tüm alanları kapsamamaktadır.","3":"Kurumun kamuoyunu bilgilendirmek üzere belirlediği ilkeler ve süreçler doğrultusunda, tüm alanları kapsayan kamuoyunu bilgilendirme uygulamalarından bazı sonuçlar elde edilmiştir. Ancak bu uygulamaların sonuçları izlenmemekte veya karar almalarda kullanılmamaktadır.","4":"Kurumun kamuoyunu bilgilendirme faaliyetlerine ilişkin bulgular izlenmekte, paydaş görüşleri alınmakta ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumun kamuoyunu bilgilendirme faaliyetleri kurumsal amaçlar ve değerler doğrultusunda, sürdürülebilir ve olgunlaşmış uygulamalarla güvence altına alınmış ve kurumun tamamında benimsenmiştir; bu hususta kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have defined principles and mechanisms to inform the public about its activities.","2":"The institution has defined a policy to adopt the principle of informing the public about its activities and has determined the methods and processes of informing the public. However, there are no practices made in line with these policies and processes, or the practices do not cover all areas.","3":"In line with the principles and processes determined by the institution to inform the public, some results have been obtained from public information practices covering all areas. However, the results of these applications are not monitored or used in decision-making.","4":"Findings regarding the institution''s public information activities are monitored, stakeholder opinions are received, and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"The institution''s public information activities are secured by sustainable and mature practices, in line with corporate goals and values, and adopted throughout the institution; The institution has many unique and innovative practices in this regard, and some of these practices are taken as an example by other institutions."}'::jsonb, '{"1":"ليس لدى المؤسسة مبادئ وآليات محددة لإعلام الجمهور بأنشطتها.","2":"وقد حددت المؤسسة سياسة لتبني مبدأ إعلام الجمهور عن أنشطتها وحددت أساليب وعمليات إعلام الجمهور. ومع ذلك، لا توجد ممارسات تتماشى مع هذه السياسات والعمليات، أو أن الممارسات لا تغطي جميع المجالات.","3":"وتمشيا مع المبادئ والعمليات التي تحددها المؤسسة لإعلام الجمهور، تم الحصول على بعض النتائج من ممارسات الإعلام العام التي تغطي جميع المجالات. ومع ذلك، لا يتم رصد نتائج هذه التطبيقات أو استخدامها في اتخاذ القرار.","4":"تتم مراقبة النتائج المتعلقة بالأنشطة الإعلامية العامة للمؤسسة، ويتم تلقي آراء أصحاب المصلحة، ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"يتم تأمين الأنشطة الإعلامية العامة للمؤسسة من خلال ممارسات مستدامة وناضجة، بما يتماشى مع أهداف وقيم الشركة، ويتم اعتمادها في جميع أنحاء المؤسسة؛ ولدى المؤسسة العديد من الممارسات الفريدة والمبتكرة في هذا الصدد، وبعض هذه الممارسات تتخذها مؤسسات أخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;
INSERT INTO public.alt_olcutler (id, kod, olcut_adi, olcut_adi_en, olcut_adi_ar, ana_baslik_id, aciklama, olusturulma_tarihi, olgunluk_duzeyleri, rubrik_aciklamalari, olgunluk_duzeyleri_en, olgunluk_duzeyleri_ar, erisim_baslangic, erisim_bitis, kalite_el_kitabi) VALUES (64, 'E.5.2', 'Hesap Verme Yöntemleri', 'Methods of Accountability', 'أساليب المساءلة', 5, NULL, '2026-05-13T02:30:32.353681', '{"1":"Kurumun hesap verme yöntemleri ve mekanizmaları bulunmamaktadır.","2":"Kurum hesap vermeyi ilkesel olarak benimsemiş, yöntem ve süreçlerini belirlemiştir. Ancak bu ilkeler ve süreçler doğrultusunda yapılmış uygulamalar bulunmamaktadır veya uygulamalar tüm alanları kapsamamaktadır.","3":"Kurumun hesap vermek üzere benimsemiş olduğu ilkeler ve süreçler doğrultusunda yaptığı uygulamalardan bazı sonuçlar elde edilmiştir. Ancak bu uygulamaların sonuçları izlenmemekte veya karar almalarda kullanılmamaktadır.","4":"Kurumun hesap verme faaliyetleri sonucunda elde edilen bulgular izlenmekte, paydaş görüşleri alınmakta ve izlem sonuçları paydaşlarla birlikte değerlendirilerek önlemler alınmaktadır.","5":"Kurumun hesap verme ilkeleri, kurumsal amaçlar ve değerler doğrultusunda, sürdürülebilir ve olgunlaşmış uygulamalarla güvence altına alınmış ve kurumun tamamında benimsenmiştir; bu hususta kurumun kendine özgü ve yenilikçi birçok uygulaması bulunmakta ve bu uygulamaların bir kısmı diğer kurumlar tarafından örnek alınmaktadır."}'::jsonb, NULL, '{"1":"The institution does not have accountability methods and mechanisms.","2":"The institution has adopted accountability as a principle and determined its methods and processes. However, there are no applications made in line with these principles and processes, or the applications do not cover all areas.","3":"Some results have been obtained from the practices carried out by the institution in line with the principles and processes it has adopted to account for it. However, the results of these applications are not monitored or used in decision-making.","4":"The findings obtained as a result of the institution''s accountability activities are monitored, stakeholder opinions are received, and the monitoring results are evaluated together with the stakeholders and precautions are taken.","5":"The accountability principles of the institution are secured by sustainable and mature practices, in line with corporate goals and values, and are adopted throughout the institution; The institution has many unique and innovative practices in this regard, and some of these practices are taken as an example by other institutions."}'::jsonb, '{"1":"لا تمتلك المؤسسة أساليب وآليات للمساءلة.","2":"لقد تبنت المؤسسة مبدأ المساءلة وحددت أساليبها وعملياتها. ومع ذلك، لا توجد طلبات تتماشى مع هذه المبادئ والعمليات، أو أن الطلبات لا تغطي جميع المجالات.","3":"وقد تم الحصول على بعض النتائج من الممارسات التي قامت بها المؤسسة بما يتوافق مع المبادئ والعمليات التي اعتمدتها لمحاسبتها. ومع ذلك، لا يتم رصد نتائج هذه التطبيقات أو استخدامها في اتخاذ القرار.","4":"تتم مراقبة النتائج التي تم الحصول عليها نتيجة لأنشطة المساءلة في المؤسسة، ويتم تلقي آراء أصحاب المصلحة، ويتم تقييم نتائج المراقبة مع أصحاب المصلحة ويتم اتخاذ الاحتياطات اللازمة.","5":"يتم تأمين مبادئ المساءلة في المؤسسة من خلال ممارسات مستدامة وناضجة، بما يتماشى مع أهداف وقيم الشركة، ويتم اعتمادها في جميع أنحاء المؤسسة؛ ولدى المؤسسة العديد من الممارسات الفريدة والمبتكرة في هذا الصدد، وبعض هذه الممارسات تتخذها مؤسسات أخرى مثالاً."}'::jsonb, NULL, NULL, '{"bgs_yeri":"","ic_paydaslar":"","dis_paydaslar":"","sorumlu_birim":"","aciklama_metni":"","aciklama_metni_en":"","uygulama_alanlari":"","ilk_planlama_tarihi":"","izleme_mekanizmalari":"","uluslararasi_paydaslar":"","performans_gostergeleri":"","degerlendirme_iyilestirme_tarihi":""}'::jsonb) ON CONFLICT (id) DO UPDATE SET olcut_adi = EXCLUDED.olcut_adi, kalite_el_kitabi = EXCLUDED.kalite_el_kitabi;

